(41, 25, 2, 'MC1ADA', '[242,244,245,241,243,246,248,247,249,251,253,252,255,250,254,260,259,256,257,258,264,261,262,265,263,267,268,266,270,269,273,274,272,271,295,276,275,278,281,279,280,284,285,282,283,292,293,294,286,287,289,290,291,288,296,277,299,297,298,305,303,302,301,300,304,329,323,306,327,354,344,324,338,332,308,351,343,325,350,322,342,307,341,320,319,331,317,345,328,335,346,352,339,340,310,333,309,347,336,321,356,326,318,316,349,355,348,334,353,337]', 0, 0, '2024-09-30 11:24:58', '2024-09-30 13:05:25');
