INSERT INTO `operators` (`id`, `name`, `email`, `password`, `created_at`, `updated_at`) VALUES
(1, 'Andre', 'danreas@localhost.com', '$2y$12$.GfXHjTY41oZ47foBBrbiOw5.V3RE.RYgR7fiJ.nzG3pjw9SbVNVa', '2024-09-16 04:54:12', '2024-09-16 04:54:12');
INSERT INTO `questions` (`id`, `question`, `scoring_type`, `category`, `image`, `option_a`, `option_b`, `option_c`, `option_d`, `option_e`, `poin_a`, `poin_b`, `poin_c`, `poin_d`, `poin_e`, `image_a`, `image_b`, `image_c`, `image_d`, `image_e`, `correct_option`, `created_at`, `updated_at`) VALUES
(4, '<p>Salah satu wujud penerapan nilai persatuan dalam implementasi menempatkan kepentingan dan keselamatan bangsa dan negara sebagai kepentingan bersama di atas kepentingan pribadi dan golongan dapat ditunjukkan pada sikap di bawah ini, yaitu …</p>', 'TWK', NULL, NULL, '<p>Mengadakan nonton bareng dengan biaya sendiri saat pertandingan Timnas Indonesia</p>', '<p>Memilih untuk tidak mudik atau pulang kampung saat pandemi COVID-19 sedang menyebar di Indonesia</p>', '<p>Lembur untuk menyelesaikan pekerjaan kantor yang harus segera dilaporkan keesokan harinya</p>', '<p>Belajar yang tekun agar kelak dapat memiliki masa depan yang cerah</p>', '<p>Bersikap netral saat teman-teman sedang membahas hal-hal terkait pasangan calon presiden dalam Pemilu</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 20:31:10', '2024-08-30 20:31:10'),
(5, '<p>Sebelum amendemen, Pasal 5 UUD 45 berbunyi “Presiden memegang kekuasaan membentuk Undang – Undang dengan persetujuan DPR”, pasca amendemen pasal tersebut berubah menjadi “Presiden berhak mengajukan rancangan Undang-Undang kepada DPR”. Perubahan pasal ini bertujuan untuk …</p>', 'TWK', NULL, NULL, '<p>Mengalihkan fungsi legislasi yang awalnya presiden menjadi kepada DPR</p>', '<p>Menghilangkan kekuasaan presiden dalam merumuskan undang-undang</p>', '<p>Mempertegas fungsi presiden dalam menjalankan undang-undang</p>', '<p>Memberikan kewenangan kepada DPR untuk menyetujui undang-undang</p>', '<p>Memperjelas bahwa DPR hanya berwenang mengajukan Rancangan Undang-Undang</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-08-30 20:32:19', '2024-08-30 20:32:19'),
(6, '<p>Hak imunitas atau kekebalan hukum merupakan hak yang diberikan konstitusi kepada DPR dalam menjalankan tugas dan fungsinya. Berikut adalah pernyatan yang tepat mengehai hak imunitas DPR adalah …</p>', 'TWK', NULL, NULL, '<p>Anggota DPR berwenang mengeluarkan produk-produk hukum negara</p>', '<p>Anggota DPR secara mutlak tidak dapat dikenakan sanksi pidana saat berinteraksi dengan masyarakat</p>', '<p>Anggota DPR tidak dapat dituntut di depan pengadilan saat melalukan kampanye politik</p>', '<p>Anggota DPR boleh melakukan penyelidikan hukum terkait kasus dan konflik yang dituntut masyarakat</p>', '<p>Anggota DPR tidak dapat dituntut di depan pengadilan karena pernyataan lisannya mengenai kredibilitas lembaga pemerintah dalam rapat DPR</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-30 20:34:13', '2024-08-30 20:34:13'),
(8, '<p>Salah satu masalah yang dialami Indoensia adalah banyaknya warga Indonesia yang masuk ke negara lain, khususnya Malaysia, secara ilegal untuk bekerja. Letak geografis Indonesia dan Malaysia yang bertetangga menjadi salah satu penyebab sering terjadinya pelanggaran tersebut. Pemerintah Malaysia pun melakukan razia TKI ilegal untuk menertibkan para TKI ilegal. Sikap pemerintah Indonesia terkait hal tersebut …</p>', 'TWK', NULL, NULL, '<p>Menghentikan pengiriman TKI ke Malaysia karena hal tersebut lebih banyak menimbulkan masalah, baik dari segi kemanusiaan maupun masalah hubungan bilateral</p>', '<p>Memberikan dukungan kepada kebijakan pemerintah Malaysia tersebut, dan tidak turut campur sedikit pun pada permasalahan hukum tersebut, karena merupakan kebijakan dalam negeri&nbsp;</p>', '<p>Mengecam aksi pemerintah Malaysia tersebut, karena bagaimana pun TKI Indonesia sendiri telah memberikan banyak kontribusi pada pemenuhan kebutuhan tenaga kerja di negara tersebut</p>', '<p>Menghormati kebijakan pemerintah Malaysia tersebut, dan mengajak Malaysia melalui jalur diplomasi untuk menemukan solusi permasalahan tersebut</p>', '<p>Meminta Malaysia segera melepaskan para TKI illegal tersebut sebagai bentuk perlindungan kepada warga negara</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 20:36:34', '2024-08-30 20:36:34'),
(9, '<p>Awal 2020 kita dikejutkan dengan masuknya pandemi Covid-19. Dalam masa pandemi tersebut, pemerintah menerapkan berbagai kebijakan untuk menyeimbangkan aspek kesehatan dan aspek ekonomi. Dari segi ekonomi, pemerintah menjaga daya beli masyarakat melalui bantuan sosial, bantuan tunai, juga program pemulihan ekonomi nasional. Dari segi kesehatan pemerintah terus berupaya memberikan batasan pergerakan masyarakat, meningkatkan sarana dan prasarana kesehatan, serta terus mengakselerasi vaksin, demi menghindari terus naiknya korban jiwa akibat pandemi Covid-19. Wacana di atas menunjukkan …</p>', 'TWK', NULL, NULL, '<p>Pandemi Covid-19 secara bersamaan memberikan kita tantangan dari segi kemanusiaan dan juga dalam upaya mewujudkan keadilan sosial</p>', '<p>Pandemi Covid-19 menuntut kita untuk dapat mengedepankan rasa persatuan untuk bersama-sama berkontribusi dalam menghadapi pandemi tersebut</p>', '<p>Masyarakat memegang peranan penting dalam upaya pemerintah melakukan penanganan Covid-19 di Indonesia</p>', '<p>Perlunya penghargaan kepada para petugas medis, instansi pemerintah yang terlibat, serta para sukarelawan yang telah bekerjasama dalam menangani pandemi Covid-19</p>', '<p>Upaya pengangan Covid-19 menjadikan banyak program bidang lainnya menjadi tertunda</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-08-30 20:37:53', '2024-08-30 20:37:53'),
(10, '<p>Gerakan Non-Blok (GNB) adalah sebuah gerakan yang diinisiaasi oleh Indonesia yang kemudian diikuti dengan keanggotaan 100 negara lainnya. Organisasi GNB sendiri adalah …</p>', 'TWK', NULL, NULL, '<p>Menyerukan perlunya dihapuskan blok barat dan blok timur pasca Perang Dunia&nbsp;</p>', '<p>Pernyataan akan ketidakberpihakan negara anggota GNB kepada pakta militer multilateral manapun</p>', '<p>Pernyataan bahwa negara anggota GNB tidak akan melakukan kerjasama dengan negara blok barat maupun blok timur</p>', '<p>Mengumpulkan negara-negara dengan paham liberalisme</p>', '<p>Menjalin kerjasama dalam pertahanan negara secara bersama-sama</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 20:38:58', '2024-08-30 20:38:58'),
(11, '<p>Sikap nasionalisme adalah rasa cinta, kesetiaan, dan kebanggaan terhadap negara tempat seseorang tinggal. Berikut pentingnya sikap nasionalisme dalam rangka menjaga hubungan antarmasyarakat demi terwujudnya persatuan dan kesatuan yaitu ….</p>', 'TWK', NULL, NULL, '<p>Nasionalisme dapat mendorong partisipasi politik yang lebih aktif. Warga negara yang merasa terhubung secara emosional dengan negara mereka cenderung lebih termotivasi untuk terlibat dalam proses politik, seperti pemilihan umum, kampanye politik, dan advokasi untuk perubahan yang mereka percayai akan memperbaiki negara mereka.</p>', '<p>Warga negara yang memiliki sikap nasionalisme yang kuat cenderung lebih berkomitmen untuk melindungi negara mereka dari ancaman baik dari dalam maupun dari luar. Mereka lebih mungkin untuk berpartisipasi dalam pertahanan negara, baik secara fisik maupun dengan mendukung kebijakan-kebijakan yang bertujuan untuk keamanan nasional.</p>', '<p>Nasionalisme juga dapat mempengaruhi perilaku konsumen. Warga negara yang nasionalis cenderung memilih untuk membeli produk-produk dalam negeri, membantu pertumbuhan ekonomi lokal dan menciptakan lapangan kerja.</p>', '<p>Sikap nasionalisme dapat memperkuat penghargaan terhadap budaya, sejarah, dan nilai-nilai negara. Ini membantu menjaga keberlanjutan dan identitas budaya suatu bangsa.</p>', '<p>Nasionalisme dapat menjadi kekuatan pemersatu yang kuat bagi suatu bangsa. Ketika warga negara memiliki kesetiaan terhadap negara mereka, mereka cenderung bersatu dalam menghadapi tantangan dan mengatasi perbedaan yang mungkin ada di antara mereka.</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-30 20:45:38', '2024-08-30 20:45:38'),
(12, '<p>Rentetan ledakan bom di Surabaya pada Mei 2018 lalu mengungkap modus baru terorisme, yakni menyertakan anak-anak kandung pelaku. Kejadian ini menyentak publik Indonesia dan dunia. Bom meledak di tiga gereja, kantor polisi, dan rumah susun di Surabaya dan Sidoarjo Jawa Timur dalam rentang waktu yang berdekatan. Kapolri Jenderal Tito Karnavian menyatakan bom yang diledakkan di tiga geraja Surabaya berjenis triacetone triperoxide (TATP) yang termasuk berkekuatan ledak tinggi (High Explosive). Bom jenis ini sering digunakan ISIS di Suriah dan Irak. Pelaku teror di Surabaya dan orang-orang yang ditangkap di Sidoarjo terkait JAD (Jamaah Ansarut Daulah) disebut merupakan pendukung utama ISIS di Indonesia. Dita Oepriarto disebutnya terkait dengan JAD. Aksi radikalisme dan terorisme yang terjadi dalam kasus di atas bertentangan dengan nilai-nilai Pancasila terutama sila ke - .....</p>', 'TWK', NULL, NULL, '<p>1</p>', '<p>2</p>', '<p>3</p>', '<p>4</p>', '<p>5</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 20:46:52', '2024-08-31 05:27:15'),
(14, '<p>Bapak&nbsp;Hafiz adalah seorang pengusaha yang menjalankan bisnis dalam bidang kuliner. Bisnis Pak Hafiz diawali dari usaha rumahan yang dijual secara online, kemudian mulai membesar dengan membuka gerai sendiri, dan akhirnya berkat usaha kerasnya akhirnya berkembang menjadi beberapa cabang. Bapak Hafiz selalu menggunakan bahan-bahan lokal dalam mengolah produknya. Sikap Pak Hafiz tersebut menunjukkan implementasi sila yang berlambang ….</p>', 'TWK', NULL, NULL, '<p>Bintang</p>', '<p>Rantai</p>', '<p>Pohon Beringin</p>', '<p>Kepala Banteng</p>', '<p>Padi dan Kapas</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-30 20:51:28', '2024-08-30 20:51:28'),
(15, '<p>Wujud sikap nasionalisme terhadap negara tidak terbatas ruang dan waktu. Begitu pula para diaspora, yang sangat penting memiliki sikap nasionalisme terhadap negaranya. Berikut ini bentuk sikap nasionalisme yang dapat dilakukan oleh diaspora diantaranya...</p>', 'TWK', NULL, NULL, '<p>Mengutamakan konsumsi produk-produk dalam negeri meskipun berada di luar negeri untuk mendukung perekonomian negara.</p>', '<p>Belajar sungguh-sungguh, menyelesaikan pendidikan, dan menerapkan ilmu yang di dapat di Indonesia.</p>', '<p>Melakukan pentas budaya di hari peringatan Kemerdekaan RI untuk mengenalkan budaya Indonesia.</p>', '<p>Memperjuangkan HAM, terutama konflik antarnegara di forum internasional.</p>', '<p>Ikut serta dalam kampanye pemanasan global dan perubahan iklim bersama mahasiswa internasional.</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-30 20:52:29', '2024-08-30 20:52:29'),
(16, '<p>Agus Salim, walau seorang pejabat, ia dan keluarganya kerap pindah-pindah rumah karena habis sewanya. Bahkan pernah, mereka tinggal di rumah yang WC-nya rusak, istrinya pun sampai muntah-muntah tak tahan. Namun Agus Salim tetap bertahan, dia bahkan tidak meminta tambahan fasilitas apapun kepada negara. Bagaimana seharusnya sikap kita sebagai generasi muda dalam meneladani nilai-nilai integritas dari kisah Agus Salim di atas?</p>', 'TWK', NULL, NULL, '<p>Selalu berkata jujur dan konsisten dalam tindakan dan perkataannya</p>', '<p>Tidak pernah mengambil keuntungan dari jabatan atau kedudukan</p>', '<p>Selalu mementingkan kepentingan pribadi di atas kepentingan bersama</p>', '<p>Selalu mengikuti aturan yang berlaku tanpa pernah melanggarnya</p>', '<p>Selalu bersemangat dalam bekerja tanpa peduli dengan kondisi pribadi</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 20:53:32', '2024-08-30 20:53:32'),
(17, '<p>Sikap integritas dalam lingkungan masyarakat yang majemuk sangat penting untuk membangun kepercayaan, harmoni, dan kerjasama antarindividu dari latar belakang yang berbeda-beda. Berikut contoh sikap integritas yang kurang relevan dalam konteks masyarakat yang majemuk adalah ….</p>', 'TWK', NULL, NULL, '<p>Bertindak sesuai dengan prinsip-prinsip moral dan etika yang universal, seperti kejujuran, tanggung jawab, dan empati.</p>', '<p>Bersikap terbuka dan menghormati pendapat, keyakinan, dan kebiasaan orang lain meskipun berbeda dengan yang diyakini.</p>', '<p>Rela berkorban untuk berkontribusi pada pembangunan masyarakat yang inklusif dan berkelanjutan.</p>', '<p>Berfokus pada kepentingan parokialisme, dan tetap memperhatikan kepentingan bersama atau kesejahteraan masyarakat secara luas.</p>', '<p>Memiliki keyakinan bahwa semua orang memiliki hak dan kesempatan yang sama, tanpa memandang latar belakang mereka</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:02:31', '2024-08-30 21:02:31'),
(19, '<p>Wujud implementasi prinsip Bhinneka Tunggal Ika dalam menghadapi keberagama vertikal di lingkungan masyarakat adalah …</p>', 'TWK', NULL, NULL, '<p>Menghargai umat beragama lain yang sedang beribadah</p>', '<p>Menjaga kelestarian budaya daerah, utamanya bahsa daerah</p>', '<p>Menjenguk tetangga yang sakit walaupun dari etnis yang berbeda</p>', '<p>Majikan memperlakukan pekerja rumah tangga dengan manusiawi</p>', '<p>Setiap daerah mendapatkan dana perimbangan dari pusat</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:05:48', '2024-08-30 21:05:48'),
(20, '<p>Pak Hendra, ketua RT di suatu perumahan, selalu menekankan kepada warganya untuk membuang sampah pada tempatnya. Ironisnya, Heri memergoki Pak Hendra membuang sampah ke sungai. Heri pun menegur Pak Hendra atas perbuatannya. Berdasarkan cerita tersebut, mengapa perbuatan Pak Hendra tidak berintegritas?</p>', 'TWK', NULL, NULL, '<p>Pak Hendra gagal menunjukkan keteladanan, memicu perilaku meniru warga, dan memperparah permasalahan sampah di lingkungan.</p>', '<p>Perbuatan Pak Hendra mencerminkan inkonsistensi antara kata-kata dan tindakannya, merusak kredibilitasnya sebagai pemimpin, dan menurunkan kepercayaan warga.</p>', '<p>Membuang sampah ke sungai merupakan tindakan ilegal dan berpotensi mencemari lingkungan, membahayakan kesehatan masyarakat, dan menyebabkan kerugian finansial.</p>', '<p>Pak Hendra tidak menunjukkan komitmen terhadap nilai-nilai integritas, melawan prinsip akuntabilitas, dan mencederai kepercayaan publik.</p>', '<p>Perbuatan Pak Hendra menunjukkan kurangnya pengetahuan tentang pengelolaan sampah, membuatnya tidak kompeten sebagai pemimpin, dan membahayakan masa depan lingkungan.</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 21:07:09', '2024-08-30 21:07:09'),
(21, '<p>Kolonialisme yang dilakukan Belanda menimbulkan berbagai reaksi dari masyarakat pribumi. Sehingga munculnya berbagai pemberontakan dari berbagai daerah. Seperti perang Cirebon (1802-1806), perang Jawa (1925-1930), perang Paderi (1821-1838), perang Banjarmasin (1825-1862). Sikap yang dapat kita teladari dari mereka adalah ....</p>', 'TWK', NULL, NULL, '<p>Nasionalisme</p>', '<p>Bela Negara</p>', '<p>Patriotisme</p>', '<p>Chauvinisme</p>', '<p>Radikalisme</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-30 21:09:59', '2024-08-30 21:09:59'),
(22, '<p>Nationale Staat pernah dialami Indonesia saat masa Kerajaan Sriwijaya dan Majapahit. Kerajaan Majapahit sendiri runtuh akibat permasalahan internal dan serangan Kerajaan Demak. Sejarah runtuhnya Kerajaan Majapahit memberikan bangsa Indonesia pelajaran bahwa …</p>', 'TWK', NULL, NULL, '<p>Kekuatan pertahanan negara sangat penting untuk mempertahanankan keamanan negara</p>', '<p>Penguatan persatuan harus dimulai dari kesadaran bangsa kita sendiri</p>', '<p>Pemimpin berperan besar dalam mempertahankan kesatuan</p>', '<p>Keberagaman sangat rentan dengan perpecahan</p>', '<p>Wilayah Kerajaan Majapahit adalah cikal lahirnya bangsa Indonesia</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 21:11:22', '2024-08-30 21:11:22'),
(24, '<p>Cerita inspirasi hidup yang membanggakan layak kita ambil dari atlet para bulutangkis Lina Marlina. Hanya lulus Sekolah Dasar (SD), dan pernah menjadi Asisten Rumah Tangga (ART) hingga supir ojek, Lina sekarang berhasil membawa harum nama Indonesia di pentas Asean Para Games Solo 2022 dengan mempersembahkan medali emas. &nbsp;Air matanya tiba-tiba berlinang ketika ditanya oleh media setelah berhasil menyumbangkan dua medali emas untuk Indonesia. Dia sendiri tidak bisa menyangka dirinya sekarang bisa menjadi seperti ini dengan bisa berprestasi dan mengharumkan nama Indonesia di ajang internasional.&nbsp;<br>Sikap kebangsaan yang dapat kita teladani dari cerita Lina Marlina yang berjuang untuk mengharumkan nama Indonesia di ajang internasional adalah ….</p>', 'TWK', NULL, NULL, '<p>Bela negara</p>', '<p>Ideologi kesatuan</p>', '<p>Patriotisme</p>', '<p>Nasionalisme</p>', '<p>Wawasan Nusantara</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-08-30 21:25:33', '2024-08-30 21:25:33'),
(25, '<p>Menjelang hari raya keagamaan biasanya marak terjadinya tindakan gratifikasi. Di bawah ini tindakan yang termasuk praktik gratifikasi adalah …</p>', 'TWK', NULL, NULL, '<p>Karena lama mengantri Tono menitipkan permohonan IMB kepada petugas yang kebetulan adalah saudaranya.</p>', '<p>Sadil menitipkan pengurusan perpanjangan STNK kepada tetangganya yang bekerja di Satlantas dan memberikan sejumlah uang.</p>', '<p>Karena berkasnya kurang, petugas perizinan meminta sejumlah uang agar izin dapat diterbitkan.</p>', '<p>Sebagai bentuk terima kasih peserta diklat CPNS memberikan bingkisan berupa kain batik kepada narasumber dari BKD.</p>', '<p>Pak RT meminta uang sebesar Rp10.000,00 untuk setiap pengajuan surat keterangan tinggal.</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:43:02', '2024-08-30 21:43:02'),
(26, '<p>Nusa merupakan seorang aparatur negara yang memiliki sebuah perusahaan yang bergerak di bidang penyediaan bahan-bahan bangunan. Saat digelar proses tender untuk proyek gedung sekolah, diam-diam perusahaan Nusa mengikuti tender tersebut. Karena Nusa kenal dengan orang yang bertugas menentukan pemenang tender, maka perusahaan Nusa kemudian dimenangkan. Contoh tersebut merupakan bentuk pelanggaran yaitu ….</p>', 'TWK', NULL, NULL, '<p>penyuapan</p>', '<p>gratifikasi</p>', '<p>penggelapan</p>', '<p>kolusi</p>', '<p>nepotisme</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-30 21:43:54', '2024-08-30 21:43:54'),
(27, '<p>Kementerian Luar Negeri RI menyelesaikan 30.894 kasus yang menjerat warga negara Indonesia (WNI) di luar negeri dalam setahun belakangan. Dijabarkan bahwa puluhan ribu kasus itu termasuk penyelamatan 422 WNI korban sindikat&nbsp;<i>online scamming</i>&nbsp;di Kamboja. Kemlu RI juga berhasil menyelamatkan 22 WNI dari ancaman hukuman mati. Selain itu, 133 WNI juga dievakuasi dari Ukraina di tengah kecamuk perang akibat invasi Rusia. Perlu dipahami bahwa Pemerintah RI mewajibkan WNI di luar negeri untuk mentaati peraturan hukum di negara di mana yang bersangkutan berada. Dengan demikian, prinsip perlindungan WNI di luar negeri bukan untuk membela yang salah atau membebaskan seorang WNI dari kewajiban dan tuntutan menurut hukum setempat, tapi untuk menjamin tersedianya keadilan bagi yang bersangkutan, apalagi berkaitan dengan statusnya sebagai seorang WNI. Hal ini menunjukkan bahwa pemerintah Indonesia …</p>', 'TWK', NULL, NULL, '<p>Telah membangun kerjasama yang baik dengan negara lain agar lebih mudah menyelesaikan kasus WNI di luar negeri</p>', '<p>Memiliki kemampuan yang cakap dalam menangani berbagai jenis permasalahan WNI di luar negeri</p>', '<p>Menjamin perlindungan kepada seluruh bangsa Indonesia dengan tetap menghormati kedaulatan negara lain</p>', '<p>Tidak dapat melakukan berbagai kebijakan terhadap WNI diluar teritorial negara Indonesia</p>', '<p>Mengembangkan kerjasama dengan bangsa lain dan ikut melaksanakan ketertiban dunia</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-30 21:45:57', '2024-08-30 21:45:57'),
(29, '<p>Perhatikan dengan saksama teks berikut!</p><p>(1) Pemerintah Indonesia telah mengakhiri status pandemi COVID-19 di tanah air pada Rabu, 21 Juni 2023. (2) Selesainya status pandemi itu ditandai dengan diterbitkannya Keputusan Presiden Republik Indonesia (Keppres) Nomor 17 Tahun 2023 tentang Penetapan Berakhirnya Status Pandemi Corona Virus Disease 2019 (Covid-19) di Indonesia. (3) Dengan adanya Keputusan Presiden yang baru, Presiden Joko Widodo juga mencabut penetapan kedaruratan kesehatan masyarakat COVID-19 dan penetapan bencana non alam penyebaran COVID-19 sebagai bencana nasional. (4) Perubahan status menjadi endemi berarti pemerintah tidak lagi intervensi apa yang harus dilakukan masyarakat dalam menangani penyakit tersebut. (5) Termasuk, soal keharusan wajib memakai masker di ruang publik.</p><p>Kalimat yang tidak efektif pada teks di atas terdapat di kalimat ke ….</p>', 'TWK', NULL, NULL, '<p>1</p>', '<p>2</p>', '<p>3</p>', '<p>4</p>', '<p>5</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-30 21:47:48', '2024-08-30 21:47:48'),
(30, '<p>Seseorang yang sedikit melakukan … dalam kesehariannya lebih … merasa …&nbsp;</p><p>Kata serapan yang tepat untuk melengkapi kalimat rumpang di atas yaitu ….</p>', 'TWK', NULL, NULL, '<p>aktifitas, beresiko, frustasi</p>', '<p>akitivitas, berisiko, frustasi</p>', '<p>aktifitas, berisiko, frustrasi</p>', '<p>aktivitas, berisiko, frustrasi</p>', '<p>aktivitas, beresiko, frustasi</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:48:42', '2024-08-30 21:48:42'),
(31, '<p>Perhatikan teks berikut!</p><p>&nbsp; G20 tidak hanya memegang pengaruh dan peran penting dalam perekonomian dunia. Negara-negara G20 juga memiliki andil besar yaitu sekitar 80 persen penyumbang emisi global. Hal ini disebabkan oleh negara-negara anggota G20 dalam menjalankan industrinya menggunakan energi fosil. Oleh sebab itu, sebagai platform kerja sama yang memegang kunci perekonomian global sekaligus menjadi sumber permasalahan penyebab krisis iklim, sudah selayaknya G20 mengambil tindakan nyata untuk mempertahankan bumi supaya tetap layak untuk ditinggali.&nbsp;<br>&nbsp; &nbsp; &nbsp; Indonesia telah menunjukkan komitmennya dalam menurunkan emisi dengan meningkatkan target Nationally Determined Contribution (NDC). Dalam dokumen NDC terbarunya, Indonesia meningkatkan target untuk menurunkan emisi dari 29 persen menjadi 31,89 persen dengan upaya sendiri dan dari 41 persen menjadi 43,20 persen dengan dukungan internasional. Meskipun target tersebut belum cukup, tetapi tetap perlu diapresiasi sekaligus diawasi. Jangan sampai implementasi penurunan emisi dimanipulasi dengan adanya greenwashing.<br>&nbsp; &nbsp; &nbsp; Momen KTT G20 menjadi momen penting untuk mengingatkan negara-negara maju untuk memenuhi janjinya memberikan dukungan bagi negara berkembang dalam hal kepentingan penurunan emisi. Oleh sebab itu transparansi dan komitmen yang tegas harus menjadi poin penting dalam pertemuan G20 ke-17 ini. Negara anggota G20 yang mendominasi penyebab emisi, negara G20 juga yang mampu dan selayaknya bertanggung jawab untuk saling bekerja sama menurunkan emisi. Karenanya, langkah dan kesepakatan yang diambil dalam pertemuan G20 sangat penting bagi keberlangsungan kehidupan di bumi.</p><p>Gagasan pokok paragraf pertama bacaan di atas yaitu ….</p>', 'TWK', NULL, NULL, '<p>KTT G20 menjadi momen penting untuk mengingatkan negara maju dalam hal kepentingan penurunan emisi.</p>', '<p>Indonesia telah menunjukkan komitmennya dalam penurunan emisi dengan meningkatkan target NDC.</p>', '<p>G20 memegang peranan dan pengaruh penting dalam perekonomian dunia.</p>', '<p>G20 menjadi sumber permasalahan krisis iklim sehingga harus melakukan tindakan nyata untuk mempertahankan bumi.</p>', '<p>Semua negara G20 menjalankan industrinya menggunakan energi fosil.</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:49:33', '2024-08-30 21:49:33'),
(32, '<p>Ia tidak pergi ke Jakarta .... menuju Bandung.&nbsp;</p><p>Isian yang tepat untuk melengkapi kalimat tersebut adalah ....</p>', 'TWK', NULL, NULL, '<p>agar</p>', '<p>melainkan</p>', '<p>dan</p>', '<p>tetapi</p>', '<p>meskipun</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 21:50:20', '2024-08-30 21:50:20'),
(34, '<p>Hubungan objek pada kalimat “Minat para pemuda untuk menjadi pilot meningkat seiring dengan perkembangan teknolog pesawat” setara dengan…</p>', 'TIU', NULL, NULL, '<p>Gubernur mengeluarkan larangan delman beroperasi di kawasan monas sehingga para kusir merasa kecewa</p>', '<p>Pacuan kuda adalah olahraga yang mengutamakan keterampilan dalam menunggang atau berlari menggunakan kuda</p>', '<p>Ali merasa bingung ingin melanjutkan sekolah penerbangan ataupun sekolah menjadi masinis setelah lulus SMA</p>', '<p>Lari estafet adalah sebuah olahraga dimana tim yang berisi empat orang berlari dengan jarak yang sama sambil membawa tongkat</p>', '<p>Kecelakaan motor dan mobil itu tak terelakkan karena kondisi cuaca ekstrim sehingga pandangan menjadi kabur</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-08-30 22:01:26', '2024-08-30 22:01:26'),
(35, '<p>Hubungan objek pada kalimat “Dian suka sekali dengan kupu-kupu namun merasa takut melihat katak” setara dengan…</p>', 'TIU', NULL, NULL, '<p>Debi mendapatkan penghidupan lewat ratusan ekor ayam yang ia kembangbiakkan</p>', '<p>Dalam peternakan kampung terdapat beberapa jenis hewan seperi sapi dan kambing</p>', '<p>Seorang pecinta kucing biasanya dikenal sebagai pendengar yang baik</p>', '<p>Jumlah penduduk Indonesia yang besar menjadi potensi bagi kekuatan pertahanan negara</p>', '<p>Saat ini umlah akomodasi kapal dan pesawat di Indonesia cukup mumpuni</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-08-30 22:03:35', '2024-08-30 22:03:35'),
(36, '<p>Hubungan objek pada kalimat “Tahun ini akan diadakan proses pemilihan presiden untuk memimpin negara dalam 5 tahun kedepan” setara dengan…</p>', 'TIU', NULL, NULL, '<p>Karena hari ini panas, ayah meminta adik untuk mengenakan topi sebagai perlindungan</p>', '<p>Dalam membangun sebuah rumah terdapat dua komponen yaitu struktur dan arsitektur</p>', '<p>Rambut adalah sel berserabut berkeratin yang terdapat hampir seluruh tubuh manusia</p>', '<p>Dalam menjaga keutuhan, kehadiran dan keaktifan ayah di keluarga adalah hal yang penting</p>', '<p>Menteri Agama hadir memberikan Instruksi dalam pelaksanaan Program Kementerian</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-08-30 22:04:30', '2024-08-30 22:04:30'),
(38, '<p>Terdapat 5 siswa sedang mengerjakan soal ujian.&nbsp;</p><p>1) Zidane mengerjakan soal lebih cepat dari Valena</p><p>2) Wulan selesai tidak lebih cepat dari Xabiru</p><p>3) Yuni selesai lebih lambat dari Valena</p><p>Jika Xabiru selesai lebih lambat dari Valena dan Yuni tidak lebih cepat dari Wulan, maka yang selesai pada urutan ke-4 adalah ....</p>', 'TIU', NULL, NULL, '<p>Zidane</p>', '<p>Valena</p>', '<p>Wulan</p>', '<p>Xabiru</p>', '<p>Yuni</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-31 00:25:37', '2024-08-31 00:25:37'),
(39, '<p>Untuk mengecek kesehatan 6 orang anak dilakukan penimbangan berat badan. Ajeng lebih berat dari Bilqis. Berat Cendikia sama dengan berat Ebiet. Fortuna lebih berat daripada Desfira. Hanya ada dua orang anak yang berat badannya sama. Pernyataan berikut yang <strong>PASTI SALAH&nbsp;</strong>adalah ...</p>', 'TIU', NULL, NULL, '<p>Bilqis lebih berat daripada Desfira</p>', '<p>Ajeng lebih berat daripada Fortuna</p>', '<p>Berat Ajeng sama dengan berat Ebiet</p>', '<p>Desfira lebih berat daripada Ajeng</p>', '<p>Desfira lebih ringan daripada Fortuna</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-08-31 00:28:43', '2024-08-31 00:28:43'),
