(121, '<p>saat anda mengetahui teman anda menyontek, apa yang anda lakukan</p>', 'TKP', NULL, NULL, '<p>tutup mata, hati dan telinga</p>', '<p>jadi cepu ke guru</p>', '<p>sorakin rame-rame</p>', '<p>menasehati dengan soundtrack eta terangkanlah</p>', '<p>menasehati dengan baik dan benar</p>', '1', '1', '1', '1', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-31 16:07:51', '2024-08-31 16:07:51'),
(122, '<p>Aplikasi CAT Trigama keren ga?</p>', 'TIU', NULL, NULL, '<p>bilang aja keren ya</p>', '<p>awas ga bilang keren lu ya</p>', '<p>liat aja lu ga bilang keren</p>', '<p>tak tunggu pulang lewat mana kalau bilang ga keren</p>', '<p>Alhamdulillah bagus dan keren kok</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-08-31 16:09:33', '2024-08-31 16:09:33'),
(124, '<p>Hubungan objek pada kalimat “Dinda menulis kata pengantar yang apik untuk mengawali novel remaja terbarunya” setara dengan…</p>', 'TIU', 'Analogi', NULL, '<p>Pemerintah sudah menyediakan stasiun pengisian daya kendaraan listrik di beberapa kota</p>', '<p>Sabri mengucapkan salam pembuka 5 agama untuk menghormati peserta seminar hari ini</p>', '<p>Semangat bela negara harus dibuktikan dengan aksi nyata, bukan hanya kata-kata</p>', '<p>Bapak terharu mendengar Deni mengucapkan ijab kabul untuk menikahi Sinta pagi tadi</p>', '<p>Pemboikotan produk-produk pro-genosida ini dilakukan atas dasar kemanusiaan</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-15 09:12:20', '2024-09-15 09:12:20'),
(125, '<p>Hubungan objek pada kalimat “Dalam buku sejarah tertulis bahwa Sultan Malikul Saleh memimpin Kerajaan Samudera Pasai selama 30 tahun” setara dengan…</p>', 'TIU', 'Analogi', NULL, '<p>Peran ayah dalam menuntun keluarganya melewati berbagai persoalan tentu sangat besar</p>', '<p>Direktur dengan berat hati memutuskan memecat Andi karena sering datang terlambat</p>', '<p>Mata uang Ringgit mengalami perlemahan 6 persen sejak awal tahun 2023 karena kenaikan suku bunga Amerika Serikat</p>', '<p>Mahatir pada tahun 1998 berusaha menyelamatkan nilai mata uangnya saat krisis ekonomi</p>', '<p>Polisi menangkap para perampok yang beraksi di rumah mewah kawasan tersebut</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-15 09:13:19', '2024-09-15 09:13:19'),
(126, '<p>Rumput berhubungan dengan ..., sebagaimana ... berhubungan dengan hewan.</p>', 'TIU', 'Analogi', NULL, '<p>ilalang – bakteri&nbsp;</p>', '<p>gulma – kambing</p>', '<p>Aljabar - Berhitung</p>', '<p>tanaman – kandang</p>', '<p>tanaman – kucing&nbsp;</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-15 09:14:17', '2024-09-15 09:14:17'),
(127, '<p>Hubungan objek pada kalimat “Ali bercita-cita menjadi astronot karena ingin mengeksplorasi ruang angkasa” setara dengan…</p>', 'TIU', 'Analogi', NULL, '<p>Murid SMA Negeri 3 diimbau untuk menggunakan masker untuk mencegah penularan COVID-19</p>', '<p>Pemerintah memutuskan untuk memberikan pengampunan pajak pada masyarakat yang mengalami kerugian akibat penyerangan ini</p>', '<p>Ayah membeli buku pelajaran dan alat tulis untuk adik karena tahun ajaran baru akan segera dimulai</p>', '<p>Lina dan tetangganya membeli ikan bawal segar itu di Pasar Almahira untuk dimasak malam ini</p>', '<p>Susi adalah seorang insinyur teknik sipil yang melakukan pengkajian di pertambangan batubara</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-15 09:15:08', '2024-09-15 09:15:08');
INSERT INTO `questions` (`id`, `question`, `scoring_type`, `category`, `image`, `option_a`, `option_b`, `option_c`, `option_d`, `option_e`, `poin_a`, `poin_b`, `poin_c`, `poin_d`, `poin_e`, `image_a`, `image_b`, `image_c`, `image_d`, `image_e`, `correct_option`, `created_at`, `updated_at`) VALUES
(128, '<p>Angkie Yudistira adalah salah satu perempuan muda berprestasi penyandang tuna rungu yang dipercayakan utnuk menjadi Staf Khusus Presiden di Bidang Sosial. Salah prestasi angkie Yudistira, yaitu pada 2011 beliau berhasil mendirikan Thisable Enterprise, dengan tujuan untuk memberdayakan kelompok disabilitas Indonesia agar memiliki kemampuan dan keterampilan, dan menyalurkannya ke dunia kerja, terutama dalam industri ekonomi kreatif. Menurut dia, saat ini kelompok disabilitas masih kesulitan dalam memperoleh pekerjaan. Prestasi yang diukir Angkie Yudhistira tersebut merupakan contoh dari implementasi sikap sila ke …</p>', 'TWK', 'Bagian 1', NULL, '<p>1</p>', '<p>2</p>', '<p>3</p>', '<p>4</p>', '<p>5</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 02:55:27', '2024-09-16 02:55:27'),
(129, '<p>Dalam kehidupan sehari-hari kita sebaiknya selalu merefleksikan nilai-nilai Pancasila. Sering kali kita tanpa sadar telah merefleksikan nilai-nilai Pancasila. Contoh implementasi nilai sila ketiga dalam kehidupan sehari-hari adalah …</p>', 'TWK', 'Bagian 1', NULL, '<p>Menggunakan produk lokal</p>', '<p>Membantu teman yang sedang tertimpa musibah</p>', '<p>Berkontribusi dengan mengeluarkan pendapat pada rapat RT</p>', '<p>Menerapkan gaya hidup hemat</p>', '<p>Memelihara tanaman di pekarangan rumah</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 02:56:12', '2024-09-16 02:56:12'),
(130, '<p>Pancasila adalah dasar negara, yang artinya dasar pengelolaan serta kebijakan pemerintah hendaknya disesuaikan dengan nilai-nilai yang ada dalam Pancasila. Di bawah ini yang merupakan praktik pengelolaan negara yang sesuai dengan nilai persatuan adalah …</p>', 'TWK', 'Bagian 1', NULL, '<p>Pemerintah menguasai seluruh sumber daya alam yang vital bagi kehidupan di wilayah negara Indonesia</p>', '<p>Pemerintah memberlakukan pajak dengan besaran yang disesuaikan dengan besaran penghasilan atau pun besaran hasil usaha</p>', '<p>Pemerintah berusaha dan memberikan kebebasan kepada warga negara untuk memilih pemimpin dan wakil rakyat melalui pemilihan langsung</p>', '<p>Pemerintah memberikan kebebasan bagi warga negara untuk mengembangkan budaya yang dimiliki setiap daerah serta mengakui keberagaman tersebut sebagai suatu &nbsp;kekayaan budaya nasional</p>', '<p>Pemerintah mengupayakan pengembangan sistem jaminan sosial bagi masyarakat dengan tujuan untuk meminimalisir terjadinya strata sosial</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 02:57:09', '2024-09-16 02:57:09'),
(131, '<p>Dalam hal Presiden/Wakil Presiden diduga melakukan pelanggaran hukum, maka DPR sebelumnya melakukan sidang paripurna untuk membahas pengajuan pemeriksaan pelanggaran hukum oleh Presiden / Wakil Presiden. Sidang tersebut harus dihadiri minimal 2/3 dari seluruh jumlah anggota DPR dan didukung oleh minimal 2/3 dari jumlah anggota yang hadir. Setelah itu DPR dapat mengajukan pemerikasaan kepada ….</p>', 'TWK', 'Bagian 1', NULL, '<p>MPR</p>', '<p>MK</p>', '<p>MA</p>', '<p>Hakim Agung</p>', '<p>Pengadilan Negeri</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 02:57:54', '2024-09-16 02:57:54'),
(132, '<p>KPU sebagai lembaga penyelenggara Pemilu baru terlembaga pasca amandemen ketiga UUD 1945. Kelembagaan KPU mengalami penguatan seiring dengan proses politik bangsa. Alasan pembentukan KPU sebagai lembaga penyelenggara pemilu adalah …</p>', 'TWK', 'Bagian 1', NULL, '<p>Agar kerahasiaan pemilu terjamin</p>', '<p>Agar terselengara pemilu yang adil, mandiri dan terbuka</p>', '<p>Untuk mempermudah pelaksanaan demokrasi dalam pemilu</p>', '<p>Merupakan permintaan masyarakat</p>', '<p>Sebagai lembaga yang menyeleksi peserta pemilihan, baik pemilihan presiden maupun legislatif</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 02:58:42', '2024-09-16 02:58:42'),
(133, '<p>Perubahan UUD 1945 meliputi sistem pelembagaan dan hubungan 3 cabang kekuasaan (legislatif, eksekutif, dan yudikatif), sistem pemerintahan lokal, pengaturan jaminan perlindungan HAM, dan berbagai sistem dalam penyelenggaraan negara (pemilihan umum, pendidikan, perekonomian dan kesejahteraan sosial, pertahanan, dan lain-lain). Di bawah ini yang bukan merupakan latar belakang khusus dilakukannya perubahan/amandemen UUD 1945 adalah ...&nbsp;</p>', 'TWK', 'Bagian 2', NULL, '<p>Banyaknya kewenangan Presiden untuk mengatur hal-hal yang penting dengan Undang-Undang sebagai konsekuensi bahwa Presiden adalah juga pemegang kekuasaan legislatif, sehingga inisiatif pengajuan RUU berasal dari Presiden</p>', '<p>Sistem ketatanegaraan yang bertumpu pada MPR sebagai pemegang kekuasaan negara tertinggi dan pelaksana sepenuhnya kedaulatan rakyat berakibat pada tiadanya checks and balances pada institusi-institusi ketatanegaraan.</p>', '<p>Kekuasaan Presiden yang terlalu dominan (executive heavy) yaitu selain sebagai pemegang kekuasaan pemerintahan (chief executive) juga sebagai kepala negara dengan hak-hak konstitusionalnya yang lazim disebut hak prerogatif, serta sekaligus memiliki kekuasaan untuk membentuk undang- undang (kekuasaan legislatif) telah menyebabkan kecenderungan lahirnya kekuasaan otoriter</p>', '<p>Konstitusi belum cukup memuat aturan dasar tentang kehidupan yang demokratis, supremasi hukum, pemberdayaan rakyat, penghormatan HAM, dan otonomi daerah, sehingga praktik penyelenggaraan negara tidak sesuai dengan Pembukaan UUD 1945</p>', '<p>Terdapat pasal-pasal yang yang terlalu umum sehingga perlu dikembangkan pasal-pasal baru sehingga lebih teknis dan tidak menimbulkan multitafsir</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 02:59:38', '2024-09-16 02:59:38'),
(134, '<p>Peristiwa Rengasdengklok adalah peristiwa penculikan terhadap Soekarno dan Hatta yang dilakukan oleh kaum muda dan terjadi pada tanggal 16 Agustus 1945. Peristiwa ini diawali atas penyerahan Jepang kepada Sekutu pada tanggal 14 Agustus 1945. Keadaan Jakarta seakan kota tak bertuan, Jepang dalam posisi gamang sementara kemerdekaan Indonesia belum diserahkan oleh Jepang. Tujuan para kaum muda menculik Soekarno-Hatta ke Rengasdengklok adalah …</p>', 'TWK', 'Bagian 2', NULL, '<p>Menyusun rencana apabila sekutu menguasai Indonesia</p>', '<p>Agar Jepang tidak menahan Soekarno-Hatta sebagai jaminan kepada sekutu</p>', '<p>Untuk mengamankan Soekarno-Hatta dari pengaruh Jepang</p>', '<p>Untuk segera merumuskan naskah proklamasi</p>', '<p>Untuk menyelamatkan Soekarno-Hatta dari serangan Jepang</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:05:36', '2024-09-16 03:05:36'),
(135, '<p>Wawasan nusantara bertujuan untuk mewujudkan rasa nasionalisme yang tinggi dalam segala aspek kehidupan rakyat Indonesia. Nantinya, hal itu akan lebih mengutamakan kepentingan nasional ketimbang kepentingan individu maupun golongan. Implementasi wawasan nusantara dalam kehidupan politik Indonesia dapat dilihat pada pilihan jawaban berikut ini, kecuali ...&nbsp;</p>', 'TWK', 'Bagian 2', NULL, '<p>Pelaksanaan kehidupan bermasyarakat, berbangsa dan bernegara harus sesuai dengan hukum yang berlaku di Indonesia tanpa pengecualian</p>', '<p>Pelaksanaan politik diatur dalam UU partai politik, pemilihan umum, pemilihan Presiden dimana pelaksanaannya sesuai hukum dan mementingkan persatuan bangsa&nbsp;</p>', '<p>Meningkatkan peran Indonesia dalam dunia internasional dan memperkuat korps diplomatik dalam upaya penjagaan wilayah Indonesia khususnya pulau terluar dan pulau kosong</p>', '<p>Mengembangkan HAM dan pluralisme dalam mempersatukan dan mempertahankan berbagai suku, agama, dan bahasa, sehingga terciptanya dan menumbuhkan rasa toleransi&nbsp;</p>', '<p>Mengembangkan kehidupan bangsa yang bersifat kedaerahan antara masyarakat yang berbeda, dari segi budaya, status sosial, maupun daerah&nbsp;</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:06:24', '2024-09-16 03:06:24'),
(136, '<p>Menteri Luar Negeri Rusia Sergey Lavrov mengapresiasi peran Indonesia dalam berbagai forum internasional. Beliau memgungkapkan bahwa, beliau melihat posisi Indonesia sebagai negara yang bertanggung jawab, yang memahami pentingnya membangun dialog berpedoman pada hukum internasional dan prinsip kedaulatan negara yang setara. Berikut adalah peran Indonesia dalam forum dan organisasi internasional, kecuali …</p>', 'TWK', 'Bagian 2', NULL, '<p>Ketua ASEAN 2023</p>', '<p>Pimpinan G20 2022</p>', '<p>Anggota G7</p>', '<p>Anggota Dewan Keamaan PBB</p>', '<p>Anggota Organisasi Kerjasama Islam (OKI)</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:07:04', '2024-09-16 03:07:04'),
(137, '<p>Bhinneka Tunggal Ika merupakan semboyan bangsa Indonesia yang mencerminkan realitas sosial budaya masyarakat Indonesia. Bagaimana implementasi Bhinneka Tunggal Ika dalam kehidupan sehari-hari di Indonesia?</p>', 'TWK', 'Bagian 2', NULL, '<p>Menerapkan aturan dan kebijakan yang sama bagi seluruh rakyat Indonesia tanpa terkecuali.</p>', '<p>Melarang adanya perbedaan pendapat dan pemikiran dalam masyarakat yang berujung konflik.</p>', '<p>Menghormati berbagai suku, agama, ras, dan golongan yang sama dalam kehidupan bermasyarakat.</p>', '<p>Menjalin toleransi dan menolak segala bentuk diskriminasi antarumat beragama.</p>', '<p>Meniadakan tradisi dan budaya lokal yang dianggap tidak sesuai dengan nilai-nilai nasional.</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:07:48', '2024-09-16 03:07:48'),
(138, '<p>Indonesia adalah negara kepulauan yang memiliki keragaman budaya, ras, suku bangsa, kepercayaan, agama, dan bahasa. Hal ini merupakan anugerah besar bagi bangsa Indonesia, namun juga dapat menjadi cikal perpecahan apabila kita tidak saling menghargai perbedaan tersebut. Sikap menghormati keberagaman bangsa adalah sebagai berikut, kecuali ….&nbsp;</p>', 'TWK', 'Bagian 3', NULL, '<p>Adanya kesadaran untuk mengutamakan kepentingan bersama diatas kepentingan pribadi</p>', '<p>Terciptanya kerukunan seperti halnya dalam keluarga</p>', '<p>Adanya semangat tolong menolong, kerjasama untuk menyelesaikan suatu masalah, dan kerja sama dalam memenuhi kebutuhan hidup</p>', '<p>Adanya kesadaran untuk menjaga keharmonisan keluarga</p>', '<p>Penyelesaian permasalahan yang ada dengan musyawarah</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:09:23', '2024-09-16 03:09:23'),
(139, '<p>Bapak Riyan adalah seorang guru pada sebuah Sekolah Menengah Atas Negeri (SMAN). Bapak Riyan melihat bahwa sesama siswa sering terjadi sindir-menyindir, maupun ejek-mengejek karena perbedaan suku maupun agama. Bapak Riyan sadar bahwa hal tersebut memang kerap dilakukan anak usia remaja yang terbilang masih baranjak dewasa. Namun dengan penuh kesadaran juga, Bapak Riyan sadar bahwa tentunya hal tersebut tetap harus diminimalisir melalui perannya sebagai seorang guru. Hal yang dapat dilakukan oleh Bapak Riyan adalah …</p>', 'TWK', 'Bagian 3', NULL, '<p>Menumbuhkan rasa bangga terhadap keberagaman di tanah air melalui &nbsp;proses belajar di sekolah</p>', '<p>Langsung menindak tegas siswa yang bersikap intoleran</p>', '<p>Memberitahukan orang tua siswa agar juga melakukan pembinaan di rumah</p>', '<p>Meminta siswa untuk bergaul secara berkelompok untuk menghindari konflik</p>', '<p>Mengajukan kepada sekolah untuk menambah jumlah jam pelajaran kewarganegaraan</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 03:12:18', '2024-09-16 03:12:18'),
(140, '<p>Perkembangan ilmu pengetahuan dan teknologi membuat masyarakat mudah untuk mengakses segaal macam informasi. Kemajuan dan kecepatan teknologi yang seperti sekarang bisa berdampak baik dan buruk. Dampak tersebut bisa berupa aktifitas dari setiap warganegara yang berkaitan dengan teknologi yang berupa akses website, juga berdampak pada kesadaran warga negara akan pentingnya membela negara. Bagaimana cara kita menyikapi perkembangan ilmu pengetahuan dan teknologi dalam konteks bela negara?</p>', 'TWK', 'Bagian 3', NULL, '<p>Ilmu pengetahuan dan teknologi baik untuk kita, dikarenakan mempermudah pekerjaan</p>', '<p>Teknologi informasi menghalangi upaya bela negara, dikarenakan membuat masyarakat terlalu berlebihan dalam mengakses informasi yang negative</p>', '<p>Ilmu pengetahuan dan teknologi baik buat warga negara Indoensia, karena dapat memberikan hiburan ditengah padatnya pekerjaan</p>', '<p>Ilmu pengetahuan dan teknologi membuat masyarakat terlena dengan modernisasi dan tidak mengembangkan jati diri bangsa, sehingga banyak kaum muda tidak mau melakukan pekerjaan di sektor pertanian dan perikanan</p>', '<p>Ilmu pengetahuan dan teknologi baik bagi setiap warga negara, terutama untuk mengenal wawasan kebangsaan, sehingga mampu memupuk rasa toleransi dan kerukunan</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:13:03', '2024-09-16 03:13:03'),
(141, '<p>Sesuai dengan prinsip negara kesatuan, maka ancaman terhadap satu daerah merupakan ancaman terhadap seluruh bangsa Indonesia. Oleh karena itu berbagai bentuk ancaman, hambatan, tantangan dan gangguan yang dihadapi bangsa Indonesia harus dapat diminimalisir, dengan tetap berpegang teguh pada prinsip bela negara demi keutuhan bangsa. Bagaimana contoh usaha yang dapat dilakukan warga negara dalam merawat bangsa Indonesia?</p>', 'TWK', 'Bagian 3', NULL, '<p>Terus belajar dan bekerja guna menjadi manusia Indonesia yang baik</p>', '<p>Dengan hanya menggunakan produk lokal saja</p>', '<p>Melakukan sosialisasi kepada masyarakat mengenai bahaya ancaman ideologi sempit</p>', '<p>Melakukan pelestarian hutan dan satwa langka</p>', '<p>Mewujudkan pemerintah yang adil dan transparan</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 03:13:53', '2024-09-16 03:13:53'),
(142, '<p>Bela negara dapat dilakukan baik secara fisik maupun non-fisik. Bela Negara secara non-fisik dapat dilakukan yang berdasarkan Pancasila dan UUD dapat dilakukan dengan berbagai cara, sepanjang masa dan dalam segala situasi, misalnya dengan cara ....</p>', 'TWK', 'Bagian 3', NULL, '<p>Pembekalan spiritual kepada masyarakat untuk menangkal masuknya semua budaya asing</p>', '<p>Meningkatkan kesadaran berbangsa dan bernegara termasuk menghayati arti demokrasi dengan menghargai pendapat orang lain dan tidak memaksakan kehendak</p>', '<p>Membantu pemerintah dalam menghalangi masuknya kapal asing yang mengancam terjadinya illegal fishing</p>', '<p>Bekerja sebagai abdi negara untuk memajukan pemerintahan</p>', '<p>Membantu penegak hukum dalam mewujudkan ketertiban di masyarakat</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:15:11', '2024-09-16 03:15:11'),
(143, '<p>Sudah 8 tahun Nusa bekerja di salah satu lembaga. Setiap bulannya total penghasilan yang didapatkan sebesar tujuh juta. Gaji tersebut hanya cukup untuk membiayai kebutuhan makan keluarga, sekolah anak, dan cicilan rumah. Saat ini Nusa bercita-cita ingin membeli mobil, apa yang sebaiknya Nusa lakukan ….</p>', 'TWK', 'Bagian 4', NULL, '<p>Mengambil setiap kelebihan uang operasional tanpa sepengetahuan pimpinan dan rekan kerja lain.</p>', '<p>Meminta kenaikan gaji keinginan untuk mempunyai mobil terfasilitasi.</p>', '<p>Berusaha mendapatkan penghasilan tambahan di luar pekerjaannya.</p>', '<p>Meminjam uang ke bagian keuangan &nbsp;untuk membayar DP mobil.</p>', '<p>Mengubur mimpinya untuk membeli mobil.</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:16:21', '2024-09-16 03:16:21'),
(144, '<p>Rika datang terlambat ke sekolah. Bu Tuti, sebagai guru piket pun langsung mencatat keterlambatan Rika. Meskipun Rika adalah Anak Kepala Dinas Pendidikan, Bu Tuti tidak takut, ia memberikan pengurangan poin kepada Rika. Rika pun kemudian diminta masuk ke ruangan kelas untuk segera mengikuti kelas Fisika. Tindakan Bu Tuti, sesuai dengan nilai integritas….</p>', 'TWK', 'Bagian 4', NULL, '<p>adil dalam bertindak</p>', '<p>professional dalam bekerja</p>', '<p>Peduli terhadap aturan sekolah</p>', '<p>jujur dalam berbuat</p>', '<p>berani dalam mengambil keputusan</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:17:00', '2024-09-16 03:17:00'),
(145, '<p>Pak Tara adalah pekerja senior yang ditugaskan untuk memberikan materi dan juga pengenalan tentang lembaga bagi para pekerja baru. Durasi waktu yang diberikan kepada Pak Tara adalah 3 jam. Karena ada suatu urusan, Pak Tara berusaha menjelaskan semuanya dengan cepat sehingga dalam satu setengah jam sudah selesai. Hal ini menunjukan bahwa Pak Tara seorang yang ….</p>', 'TWK', 'Bagian 4', NULL, '<p>Bekerja semaunya</p>', '<p>Tidak memiliki semangat bekerja</p>', '<p>Tidak bertanggung jawab</p>', '<p>Melakukan korupsi terhadap waktu kerja</p>', '<p>Kreatif dan tidak bertele-tele</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:17:41', '2024-09-16 03:17:41'),
(146, '<p>Keindahan dan kebersihan dalam ruang kerja dapat memicu semangat dalam melaksanakan tugas. Suatu hari Anda melihat begitu banyak sampah yang berserakan di ruangan kantor, padahal di setiap meja kerja sudah disediakan tong sampah. Sebagai orang yang berintegritas, apa yang akan Anda lakukan ….</p>', 'TWK', 'Bagian 4', NULL, '<p>Mengabaikan saja apa adanya karena bukan tanggung jawab Anda.</p>', '<p>Memasukan sampah yang berserakan ke tong sampah.</p>', '<p>Segera memanggil petugas kebersihan untuk membersihkan ruangan kerja.</p>', '<p>Memasukan sampah yang berserakan dengan hati kesal.</p>', '<p>Memberikan peringatan rekan kerja agar memasukan sampah pada tempatnya.</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:18:24', '2024-09-16 03:18:24'),
(147, '<p>Pada masa pemilu banyak partai politik melakukan kampanye dalam rangka mencari dukungan untuk kandidat kepala daerah yang diusungnya. Dalam melakukan kampanyenya, seorang calon kepala daerah banyak memberikan janji-janji kepada masyarakat. Jika ia merupakan orang yang berintegritas, manakah yang sebaiknya dilakukan jika ia berhasil terpilih ….</p>', 'TWK', 'Bagian 4', NULL, '<p>Menggunakan uang pribadinya untuk kepentingan masyarakat.</p>', '<p>Berkomitmen untuk tidak mengambil gaji selama menjabat.</p>', '<p>Berusaha menunaikan semua janji-janji kampanyenya.</p>', '<p>Menunjukan etos kerja yang tinggi dengan pulang paling akhir.</p>', '<p>Memberikan hadiah kepada tim sukses yang telah bekerja keras untuknya.</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:19:09', '2024-09-16 03:19:09'),
(148, '<p>Karena belum ada Lambang Negara Garuda Pancasila, Anda diminta untuk memasang di ruangan yang baru saja selesai direnovasi. Selain itu juga ada foto presiden dan wakil presiden yang harus dipasang. Dalam hal pemasangan, apa yang akan Anda lakukan?</p>', 'TWK', 'Bagian 5', NULL, '<p>Foto presiden dan wakil presiden ditempatkan sejajar dan dipasang lebih tinggi dari Garuda Pancasila. Foto presiden dipasang disebelah kanan dan foto wakil presiden dipasang sebelah kiri dari Garuda Pancasila.</p>', '<p>Foto presiden dan wakil presiden ditempatkan sejajar dan dipasang lebih rendah dari Garuda Pancasila. Foto presiden dipasang disebelah kiri dan foto wakil presiden dipasang sebelah kanan dari Garuda Pancasila.</p>', '<p>Foto presiden dan wakil presiden ditempatkan sejajar dan dipasang lebih tinggi dari Garuda Pancasila. Foto presiden dipasang disebelah kiri dan foto wakil presiden dipasang sebelah kanan dari Garuda Pancasila.</p>', '<p>Foto presiden dan wakil presiden ditempatkan sejajar dan dipasang lebih rendah dari Garuda Pancasila. Foto presiden dipasang disebelah kanan dan foto wakil presiden dipasang sebelah kiri dari Garuda Pancasila.</p>', '<p>Foto presiden dan wakil presiden ditempatkan sejajar dengan Garuda Pancasila. Foto presiden dipasang disebelah kanan dan foto wakil presiden dipasang sebelah kiri dari Garuda Pancasila.</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:20:11', '2024-09-16 03:20:11'),
(149, '<p>Sebelum masa kemerdekaan Indonesia menghadapi ancaman berupa agresi militer dari negara penjajah. Sekarang Indonesia menghadapi ancaman agresi nonmiliter dari negara lain. Salah satu contohnya adalah ….</p>', 'TWK', 'Bagian 5', NULL, '<p>menerima hibah dari negara asing dalam rangka restrukturisasi wilayah bencana</p>', '<p>masuknya kebudayaan asing yang tidak sesuai kebudayaan Indonesia</p>', '<p>Indonesia menjadi presidensi pelaksanaan G20.</p>', '<p>Indonesia mengirim pasukan Garuda ke Lebanon.</p>', '<p>Indonesia mengekspor barang kerajinan ke negara lain.</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:20:57', '2024-09-16 03:20:57'),
(150, '<p>Lirik lagu Indonesia Raya ditulis oleh komposer sekaligus wartawan Wage Rudolf Supratman. Mulanya, WR Supratman adalah wartawan koran Sin Po yang ditugaskan untuk meliput Kongres Pemuda II, seperti ditulis oleh St. Sularto dalam “Wage Rudolf Supratman Menunggu Pelurusan Fakta Sejarah” di Majalah Prisma edisi 5 Mei 1983. Namun, kala itu keinginannya tidak hanya sekadar menulis berita, tetapi juga ingin membawakan lagu \"Indonesia Raya\". Atas inisiatifnya sendiri, ia menyebarkan salinan lagu itu kepada para pimpinan organisasi pemuda. Awalnya Supratman hanya memainkan instrumen lagu saja dengan biolanya. Setelah selesai memainkan instrumen \"Indonesia Raya\", para hadirin meminta agar lagu tersebut dinyanyikan. Setelah melalui diskusi, akhirnya \"Indonesia Raya\" dinyanyikan dengan sedikit perubahan lirik.&nbsp;Alasan dilakukan perubahan lirik tersebut adalah ….</p>', 'TWK', 'Bagian 5', NULL, '<p>Terdapat kata yang kurang pantas untuk ada di sebuah lagu nasional.</p>', '<p>Lirik yang digunakan tidak sesuai dengan notasi nada yang seharusnya.</p>', '<p>Takut menimbulkan kecurigaan dari pemerintah Kolonial Belanda yang saat itu berkuasa.</p>', '<p>Kata yang digunakan memuat kata yang tidak berbahasa Indonesia sehingga harus disesuaikan.</p>', '<p>Pemerintah Kolonial Belanda meminta menghapus kata yang dianggap tidak pantas dan merendahkan Pemerintah Belanda.</p>', '0', '0', '5', '0', '0', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:21:36', '2024-09-16 03:21:36'),
(151, '<p>Ancaman terbesar dari keamanan nasional saat ini tidak berupa agresi dari luar, tetapi disintegrasi bangsa. Salah satu konflik vertikal yang dapat mengancam integrasi nasional adalah ….</p>', 'TWK', 'Bagian 5', NULL, '<p>konflik antarsuku</p>', '<p>konflik antaragama</p>', '<p>konflik antarkelompok</p>', '<p>konflik antarbangsa</p>', '<p>konflik penggusuran proyek pemerintah</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:22:13', '2024-09-16 03:22:13'),
(152, '<p>Adanya budaya gotong royong yang terdapat di lingkungan pedesaan menjadi hal yang begitu berharga. Contoh jika ada tetangga yang rumahnya rusak akibat musibah masyarakat segera datang untuk membantu. Berbeda dengan masyarakat di perkotaan, meskipun mereka dalam satu perumahan yang sama tetapi tidak saling kenal. Mereka menyibukan diri dengan kepentingan pribadi. Fenomena tersebut merupakan pengaruh modernisasi pada aspek ...</p>', 'TWK', 'Bagian 5', NULL, '<p>Sosial</p>', '<p>Ekonomi</p>', '<p>Politik</p>', '<p>Hukum</p>', '<p>Pendidikan</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 03:23:25', '2024-09-16 03:23:25'),
(153, '<p>Bacalah paragraf di bawah ini dengan saksama!</p><p>Tampaknya kepekaan kita pelan-pelan menyusut setelah tragedi demi tragedi itu kini hampir menjadi rutin. Kita khawatir, lama-lama semua menjadi biasa dan tidak ada lagi rasa sedih dan berduka. Sebab biasanya, sesuatu yang menjadi rutin tidak lagi mengusik kita. Ia seakan kehilangan makna, sama seperti kita membaca berita perampokan, penodongan, pemerkosaan, pembunuhan, dan sebagainya di sekitar kita. Paling-paling kita hanya bergumam pendek. Setelah itu, kita pun melupakannya dan kita tidak berpikir terlalu jauh.</p><p>&nbsp;</p><p>Gagasan pokok paragraf tersebut adalah ....</p>', 'TWK', 'Bagian 6', NULL, '<p>hal-hal yang menyeramkan sekitar bencana</p>', '<p>menyusutnya kepekaan atas tragedi</p>', '<p>keengganan membantu korban bencana</p>', '<p>hilangnya makna gotong royong</p>', '<p>berita tentang tragedi menyakitkan</p>', '0', '5', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:24:23', '2024-09-16 03:24:23'),
(154, '<p>Sarireja menjadi brand ternama untuk kosmetik di Indonesia. Pemilik mengawali &nbsp;dengan membuka salon kecil di halaman rumahnya. Saat memperluas jaringan usahanya ke beberapa pusat perbelanjaan mendapatkan penolakan. Penolakan itu tidak menyurutkan semangatnya. Kemudian ia membangun sendiri toko yang menjual kosmetik. Akhirnya brand tersebut berkembang pesat dan memiliki 20 cabang usaha.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<br>Dari kisah di atas, pelajaran yang dapat diambil adalah ….</p>', 'TWK', 'Bagian 6', NULL, '<p>Bisnis kosmetik memiliki peluang besar untuk sukses.</p>', '<p>Bisnis kosmetik memiliki peluang besar untuk sukses.</p>', '<p>Strategi pemasaran yang tepat digunakan dengan menjual ke orang-orang.</p>', '<p>Kegagalan tidak menjadi penghalang untuk tetap berusaha dan meraih kesuksesan.</p>', '<p>Awali bisnis dengan usaha yang sederhana.</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:25:34', '2024-09-16 03:25:34'),
(155, '<p>Ibu membeli: tas, baju, sepatu dan payung di pasar.</p><p>Kesalahan penggunaan tanda baca yang terdapat pada kalimat tersebut adalah ....</p>', 'TWK', 'Bagian 6', NULL, '<p>Penggunaan tanda titik dua dan setelah kata sepatu seharusnya diberi tanda koma.</p>', '<p>Penggunaan tanda titik dua sebelum kata tas seharusnya diganti dengan tanda titik koma.</p>', '<p>Penggunaan tanda titik dua dan tanda titik setelah kata pasar.</p>', '<p>Penggunaan tanda titik dua dan tanda koma setalah kata tas.</p>', '<p>Penggunaan tanda koma setalah kata tas dan baju.</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 03:26:27', '2024-09-16 03:26:27'),
(156, '<p><strong>Perhatikan teks berikut!</strong></p><p>(1) Kota Bogor adalah sebuah kota di provinsi Jawa Barat, Indonesia. (2) Kota ini terletak 59 km sebelah Selatan Jakarta. (3) bogor dikenal dengan julukan kota hujan, karena memiliki curah hujan yang sangat tinggi. (4) Kota Bogor terdiri atas 6 kecamatan yang dibagi lagi atas sejumlah 68 kelurahan.&nbsp; (5) Kecamatan yang paling kecil di Kota Bogor adalah Kecamatan Bogor selatan.</p><p><br>Kalimat dengan penulisan huruf kapital yang tepat terdapat pada nomor ....</p>', 'TWK', 'Bagian 6', NULL, '<p>1</p>', '<p>2</p>', '<p>3</p>', '<p>4</p>', '<p>5</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:26:54', '2024-09-16 03:26:54'),
(157, '<p>Baiq, Pidi, 2014.&nbsp;<i>Dia adalah Dilanku Tahun 1990</i>. Jakarta; Pastel Books.</p><p>Perbaikan penulisan tanda baca pada daftar pustaka tersebut adalah ....</p>', 'TWK', 'Bagian 6', NULL, '<p>Baiq, Pidi, 2014,&nbsp;<i>Dia adalah Dilanku Tahun 1990,</i>&nbsp;Jakarta, Pastel Books.</p>', '<p>Baiq, Pidi. 2014.&nbsp;<i>Dia adalah Dilanku Tahun 1990.</i>&nbsp;Jakarta. Pastel Books.</p>', '<p>Baiq, Pidi, 2014,&nbsp;<i>Dia adalah Dilanku Tahun 1990</i>, Jakarta: Pastel Books.</p>', '<p>Baiq. Pidi, 2014.&nbsp;<i>Dia adalah Dilanku Tahun 1990</i>. Jakarta: Pastel Books.</p>', '<p>Baiq, Pidi. 2014.&nbsp;<i>Dia adalah Dilanku Tahun 1990.</i>&nbsp;Jakarta: Pastel Books.</p>', '0', '0', '0', '0', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:27:47', '2024-09-16 03:27:47'),
(158, '<p>Rekan kerja di kantor baru saja melakukan kesalahan bahwa ia memalsukan beberapa angka di dalam laporan keuangan, sehingga Dika yang juga berpartner dengannya dalam membuat laporan kena tegur atasan. Sikap Dika kepada rekan tersebut ….</p>', 'TKP', 'Random', NULL, '<p>Memilih menjauhi karena ia sudah membuat Anda mendapat masalah</p>', '<p>Mengatakan padanya agar bekerja lebih profesional lagi</p>', '<p>Mengatakan bahwa jangan lagi melibatkan Anda atas kesalahan yang ia lakukan</p>', '<p>Menggunjingkan dengan teman</p>', '<p>Mengatakan bahwa Anda kesal dengan perbuatannya</p>', '3', '5', '4', '1', '2', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:32:01', '2024-09-16 03:32:01'),
(159, '<p>Rekan kerja di kantor sering sekali menyindir Andri bahkan untuk hal-hal sepele yang seharusnya tidak dikait-kaitkan dengan pekerjaan kantor. Sikap Andri ….</p>', 'TKP', 'Random', NULL, '<p>Membiarkan karena tidak ingin menjadikan masalah</p>', '<p>Mengatakan bahwa Andri tidak suka dengan sikapnya</p>', '<p>Mengabaikan namun jika Andri mulai terganggu lebih baik mengatakan bahwa ia kurang suka dengan caranya</p>', '<p>Membalas menyindir agar ia juga bisa berkaca</p>', '<p>Melapor kepada atasan karena Andri merasa kesal</p>', '3', '4', '5', '1', '2', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:33:02', '2024-09-16 03:33:02'),
(160, '<p>Anda harus segera mengunggah surat edaran di website, namun ternyata teman Anda yang seharusnya mengoreksi surat edaran tersebut dan memastikan bahwa sudah ditandatangi atasan malah lalai. Ia belum menyelesaikan tugasnya. Saat, Anda tagih ia juga tidak langsung mengerjakan. sikap Anda ….</p>', 'TKP', 'Random', NULL, '<p>Menegurnya dan mengingatkan agar segera mengerjakannya karena&nbsp;sudah harus diunggah</p>', '<p>Mengatakan bahwa Anda akan mengerjakan sendiri karena kerja rekan&nbsp;Anda lamban</p>', '<p>Menegurnya dan akan melapor kepada atasan jika ia masih bersantai&nbsp;</p>', '<p>Marah kepadanya karena lalai terus-terusan</p>', '<p>Mengingatkan akan tugas-tugas dan tanggungjawabnya agar ia tidak&nbsp;berbuat kelalaian lagi</p>', '4', '2', '5', '1', '3', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:34:24', '2024-09-16 03:34:24'),
(161, '<p>Anda sedang mengerjakan laporan dengan suatu aplikasi, tiba-tiba aplikasi&nbsp;tersebut error. Anda sudah mencoba mengutak-atik, namun belum berhasil. Anda&nbsp;ingin meminta bantuan teman Anda namun terlihat ia sedang sibuk. Sikap Anda ….</p>', 'TKP', 'Random', NULL, '<p>Menunggu sekiranya teman sudah tidak sibuk</p>', '<p>Bertanya apakah bisa dimintai bantuan oleh Anda</p>', '<p>Meminta maaf dan mencoba mengutarakan maksud meski ia sedang sibuk karena Anda juga butuh dibantu</p>', '<p>Meminta maaf dan bertanya apakah bisa menganggu sebentar untuk&nbsp;menanyakan keluhan Anda</p>', '<p>Memilih tidak jadi meminta bantuan karena tidak enak hati&nbsp;</p>', '2', '3', '4', '5', '1', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:35:08', '2024-09-16 03:35:08'),
(162, '<p>Rika merupakan customer service di sebuah toko online. Suatu ketika ada seorang customer melapor bahwa barang yang ia beli di toko Anda ternyata ada cacat. Sikap Rika….</p>', 'TKP', 'Random', NULL, '<p>Meminta maaf dengan tulus</p>', '<p>Meminta maaf dan akan segera menggantinya</p>', '<p>Meminta maaf dan mengusulkan agar ia mengajukan pengembalian di&nbsp;marketplace</p>', '<p>Meminta maaf dan berjanji akan lebih baik dalam pelayanan</p>', '<p>Mendengarkan keluhannya tanpa mengganti barang yang cacat&nbsp;</p>', '2', '4', '5', '3', '1', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:36:02', '2024-09-16 03:36:02'),
(163, '<p>Ada seorang pelanggan datang dan ingin mengganti ban mobilnya di bengkel milik Anda. Padahal 15 menit lagi bengkel akan tutup, maka sikap Anda ….</p>', 'TKP', 'Random', NULL, '<p>Menolaknya dan menyarankan mencari bengkel lain</p>', '<p>Melayaninya terlebih dulu baru menutup bengkel&nbsp;</p>', '<p>Melayaninya dengan tarif lebih</p>', '<p>Melayaninya namun jika memang belum selesai saat jam bengkel tutup&nbsp;mengatakan mobilnya ditinggal saja akan dilanjutkan besok</p>', '<p>Meminta maaf tidak bisa melayani</p>', '2', '5', '1', '3', '4', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:40:51', '2024-09-16 03:40:51'),
(164, '<p>Seorang mahasiswa protes karena nilainya semester ini tidak keluar di KRS. Ia&nbsp;datang ke bagian prodi kampus dan bertanya pada bagian akademik. Ternyata&nbsp;setelah Anda cek, nilai sudah tercantum namun Anda lalai dalam melakukan input&nbsp;di KRS miliknya. Sikap Anda ….</p>', 'TKP', 'Random', NULL, '<p>Seorang mahasiswa protes karena nilainya semester ini tidak keluar di KRS. Ia&nbsp;datang ke bagian prodi kampus dan bertanya pada bagian akademik. Ternyata&nbsp;setelah Anda cek, nilai sudah tercantum namun Anda lalai dalam melakukan input&nbsp;di KRS miliknya. Sikap Anda ….</p>', '<p>Langsung memperbaiki agar masalah selesai</p>', '<p>Meminta maaf dan berjanji akan segera memperbaiki</p>', '<p>Meminta maaf dan melakukan input saat itu juga</p>', '<p>Mengatakan akan memperbaiki jika Anda sudah tidak sibuk</p>', '2', '4', '3', '5', '1', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:41:37', '2024-09-16 03:41:37'),
(165, '<p>Tika sedang berjaga di loket pendaftaran rumah sakit. Ketika ada nenek tua datang namun ia buta huruf dan kebingungan dengan arahan Tika. Sikap Tika….</p>', 'TKP', 'Random', NULL, '<p>Mengulang penjelasan hingga dapat dipahami nenek tersebut</p>', '<p>Menelpon bagian keamanan untuk membantu nenek tersebut</p>', '<p>Menelpon teman Tika yang berjaga di poli dan mengatakan agar menjemput seorang nenek di bagian pendaftaran</p>', '<p>Memberi petunjuk arah ke nenek tersebut lokasi poli yang dituju</p>', '<p>Mengantarkan nenek tersebut ke poli yang dituju agar tidak bingung</p>', '1', '3', '4', '2', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:43:01', '2024-09-16 03:43:01'),
(166, '<p>Ketika mempersentasikan produk baru, maka yang akan Anda lakukan adalah ….</p>', 'TKP', 'Random', NULL, '<p>Membuat slide presentasi dengan animasi menarik agar bisa diterima&nbsp;</p>', '<p>Berkomunikasi dengan bahasa yang baik dan mudah dimengerti&nbsp;</p>', '<p>Komunikatif, dan menampilkan slide yang menarik</p>', '<p>Memilih lebih banyak interaksi dengan audiens</p>', '<p>Banyak memperkenalkan keunggulan produk</p>', '3', '4', '5', '1', '2', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:43:44', '2024-09-16 03:43:44'),
(167, '<p>Ketika harus mengupload data-data yang digunakan sebagai syarat kelengkapan&nbsp;pendaftaran CPNS ternyata server tidak bisa dibuka, sikap Anda...</p>', 'TKP', 'Random', NULL, '<p>Panik dan berusaha tetap berusaha berfikir untuk menemukan solusi</p>', '<p>Bertanya pada teman lain sesama pejuang NIP</p>', '<p>Memilih mencari akun media sosial BKN dan lainnya untuk memantau informasi terkait masalah penguploadan data</p>', '<p>Mencari tahu ke ahli IT terkait permasalahan yang sedang dihadapi</p>', '<p>Menundanya namun sering memantau agar ketika server sudah selesai&nbsp;maintenance langsung bisa upload</p>', '1', '4', '5', '2', '3', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:45:11', '2024-09-16 03:45:11'),
(168, '<p>Andi melihat bahwa temannya, Rini yang juga ASN di Pemda ternyata masih sering mengunggah beberapa pernyataan di laman media sosialnya terkait dukungannya kepada berdirinya negara yang berlandaskan agama tertentu dan menggantikan dasar negara pancasila. Meskipun dalam beberapa kesempatan, Andi telah mengingatkannya. Menyikapi hal itu, maka Andi selaku rekan kerja yang terbilang dekat dengannya adalah….</p>', 'TKP', 'Random', NULL, '<p>Berkomentar secara pribadi terkait hal ini kepada yang bersangkutan</p>', '<p>Mengutarakan kepada atasan agar diadakan pembinaan pancasila dan UUD 1945 kepada rekan tersebut</p>', '<p>Menegur dengan tegas, tindakannya bisa membahayakan banyak pihak</p>', '<p>Mengingatkan akan NKRI dan pancasila kepadanya</p>', '<p>Memilih membicarakan dengan teman lain, siapa tahu bisa tercerahkan</p>', '2', '5', '4', '3', '1', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:48:57', '2024-09-16 03:48:57'),
(169, '<p>Suatu ketika, Doni menerima sebuah brosur bahwa akan diadakan pelatihan kepemimpinan gratis dari suatu organisasi. Doni pun tertarik dan ikut serta dalam kegiatan tersebut. Di penghujung kegiatan, ternyata ada ajakan untuk mendeklarasikan negara atas dasar agama dan menyudutkan pancasila serta sistem demokrasi. Sikap Doni menghadapi ajakan tersebut ….</p>', 'TKP', 'Random', NULL, '<p>Menerima meski terpaksa karena menghargai pelatihan kepemimpinannya</p>', '<p>Menolak dengan santun agar tidak menyinggung</p>', '<p>Melapor kepada RT serta mengajak masyarakat beramai-ramai melakukan penggerebekan</p>', '<p>Melapor kepada RT serta mengajak masyarakat beramai-ramai melakukan penggerebekan</p>', '<p>Menolak dengan tegas dan berusaha melaporkan kepada pihak berwenang</p>', '1', '2', '4', '3', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:51:11', '2024-09-16 03:51:11'),
(170, '<p>Ketika mendapati tetangga yang kebetulan berjualan di dekat sungai namun membuang sampah daun bekas bungkus barang dagangannya di sungai. Sikap Andi selaku warga yang juga tinggal di dekat sungai adalah ...</p>', 'TKP', 'Random', NULL, '<p>Menegurnya agar tidak membuang sampah sembarangan</p>', '<p>Memberi tulisan peringatan di dekat sungai</p>', '<p>Membiarkannya karena tidak enak hati</p>', '<p>Mengatakan bahwa lebih baik menyediakan tempat sampah dan membuangnya di tempat yang sudah disediakan</p>', '<p>Menyuruhnya lebih baik membakar sampah daripada membuang sampah&nbsp;di sungai</p>', '3', '4', '2', '5', '1', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:51:54', '2024-09-16 03:51:54'),
(171, '<p>Seorang teman mengundang Budi ke rumahnya untuk mengikuti acara syukuran aqiqah anaknya. Budi tidak suka daging kambing, maka saat disajikan menu hidangan olahan kambing sikap Budi….</p>', 'TKP', 'Random', NULL, '<p>Menolak dengan sopan karena kurang begitu suka dengan daging olahan kambing</p>', '<p>Meminta maaf bahwa tidak suka kambing, dan bila berkenan meminta agar menu tersebut dibungkus untuk keluarga dirumah</p>', '<p>Mencicipi sedikit saja sebagai bentuk menghormati tuan rumah</p>', '<p>Memilih untuk menikmati hidangan tersebut dengan lahap meskipun mual</p>', '<p>Mengatakan bahwa Anda memilih untuk menikmati snack saja</p>', '2', '3', '5', '4', '1', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 03:54:09', '2024-09-16 03:54:09'),
(172, '<p>Terhadap segala aktivitas keagamaan yang mengarah kepada radikalisme dan&nbsp;terorisme dengan dalih jihad maka sikap Anda ….</p>', 'TKP', 'Random', NULL, '<p>Menolak keras dan tidak akan mengikuti aksi terorisme</p>', '<p>Menolak meski tidak secara langsung</p>', '<p>Tidak mau banyak berkomentar karena takut dengan ancaman</p>', '<p>Menghindarinya karena takut ancaman hukuman</p>', '<p>Menolak dan melapor kepada polisi</p>', '4', '3', '1', '2', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 03:54:50', '2024-09-16 03:54:50'),
(173, '<p>Di saat sedang browsing santai di media sosial, tiba-tiba anda mendapatkan notifikasi email bahwa ada percobaan masuk ke salah satu akun media sosial Anda. Mengetahui hal tersebut, sikap Anda ...</p>', 'TKP', 'Random', NULL, '<p>Panik dan segera memberi pengumuman takut media sosial&nbsp;disalahgunakan</p>', '<p>Segera mengganti password dan melihat apakah ada kejanggalan dengan akun Anda</p>', '<p>Melakukan pengecekan terhadap media sosial Anda, barangkali ada pembajakan terhadap konten-konten Anda</p>', '<p>Mengumumkan ke media sosial bahwa akun anda kemungkinan telah di retas dan saat ini sedang dilakukan pengecekan</p>', '<p>Memilih membuat akun baru dengan password yang memiliki tingkat kerumitan lebih tinggi</p>', '1', '5', '4', '3', '2', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:55:45', '2024-09-16 03:55:45'),
(174, '<p>Anin kembali meminta bantuan dalam mengoperasikan suatu aplikasi di komputer, padahal Andika sudah pernah&nbsp; mengajarinya dengan detail. Suatu ketika saat ia kembali meminta tolong untuk diajari, situasi Andika sedang banyak pekerjaan, maka sikap Andika ….</p>', 'TKP', 'Random', NULL, '<p>Mengajarinya meski sebentar karena tidak enak hati&nbsp;</p>', '<p>Meminta maaf dan berjanji akan mengajari Anin setelah Andika selesai mengerjakan tugas</p>', '<p>Mengatakan lebih baik meminta tolong teman lain saja, karena Andika masih sibuk</p>', '<p>Meminta maaf belum bisa membantu dan mengarahkannya ke video tutorial untuk dipelajari</p>', '<p>Mengajarinya dengan detail meski pekerjaan Andika terbengkalai&nbsp;</p>', '3', '4', '1', '5', '2', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 03:56:50', '2024-09-16 03:56:50'),
(175, '<p>Instansi Anda menerapkan kebijakan sistem pelaporan dan pengisian data administrasi secara online demi meningkatkan pelayanan, sehingga setiap orang wajib melakukan pemanfaatan layanan secara online. Namun ada masyarakat yang protes bahwa tidak semua masyarakat mampu menggunakan teknologi tersebut. Menyikapi hal tersebut, menurut Anda ...</p>', 'TKP', 'Random', NULL, '<p>Mengatakan bahwa sudah seharusnya masyarakat mau menerima&nbsp;keberadaan teknologi</p>', '<p>Mencoba menengahi dengan cara menugaskan petugas khusus untuk memandu layanan secara online</p>', '<p>Memilih membuka kembali loket antrean manual agar masyarakat yang&nbsp;tidak kenal teknologi bisa terlayani juga</p>', '<p>Tetap membuka loket manual sembari mensosialisasikan kemudahan pelaporan secara online</p>', '<p>Bingung dan tidak terlalu ambil pusing terhadap kritikan</p>', '2', '5', '3', '4', '1', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:57:45', '2024-09-16 03:57:45'),
(176, '<p>Seorang rekan kerja protes bahwa file laporan yang Adit kirim berantakan. Setelah dicek ternyata tampilan tulisan dalam file menjadi tanpa spasi, hal ini bisa dikarenakan software di komputer teman kantor Adi masih versi lama sehingga kurang support. Maka yang Adi lakukan?</p>', 'TKP', 'Random', NULL, '<p>Membiarkannya karena Adit juga ada kerjaan lain</p>', '<p>Memilih membetulkan dengan cara menyimpan pekerjaan di aplikasi&nbsp;yang lebih lama agar terbaca di komputer teman Anda</p>', '<p>Menyuruh teman Anda mengupgrade komputernya agar bisa support</p>', '<p>Mengatakan agar teman Anda usaha sendiri memperbaikinya</p>', '<p>Meminta agar teman Anda mencari tahu penyebabnya melalui ahli IT</p>', '2', '5', '3', '1', '4', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:58:44', '2024-09-16 03:58:44'),
(177, '<p>Adanya sistem informasi dan media massa yang sangat berkembang dewasa ini menyebabkan banyak pelajar mengikuti tren dari luar. Pelajar mudah terlibat kenakalan remaja seperti membolos, tawuran, bahkan sampai terindikasi pemakaian obat-obatan terlarang. Hal ini juga dipengaruhi oleh faktor pergaulan di kalangan remaja. Secara tidak langsung, hal tersebut berdampak buruk bagi pelajar itu sendiri, seperti degradasi moral, sampai hancurnya masa depan mereka. Upaya yang tepat untuk dilakukan oleh pihak sekolah guna mengatasi gejala sosial tersebut adalah…</p>', 'TKP', 'Random', NULL, '<p>Menambah jam belajar peserta didik sampai sore</p>', '<p>Memberi sanksi tegas bagi yang melanggar tata tertib sekolah</p>', '<p>Mewajibkan peserta didik mengikuti semua kegiatan ekstrakurikuler</p>', '<p>Melaporkan peserta didik yang melanggar tata tertib sekolah kepada pihak berwajib</p>', '<p>Memberi tugas atau pekerjaan rumah kepada peserta didik</p>', '1', '5', '4', '3', '2', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 03:59:27', '2024-09-16 03:59:27'),
(178, '<p>Ronal dinilai cukup vokal dalam memaksakan keyakinannya kepada orang lain secara nyata termasuk temannya sendiri. Hal ini terjadi karena banyaknya organisasi yang diragukan kebenarannya, tetapi tetap saja masih banyak pengikutnya. Menurut Anda sebaiknya Ronal ...</p>', 'TKP', 'Random', NULL, '<p>Lebih selektif lagi dalam memilih organisasi terutama organisasi keagamaan</p>', '<p>Bersikap biasa saja karena faktor eksternal tidak terlalu berpengaruh dalam penciptaan sikap radikal</p>', '<p>Mengubah sifat buruk yang selalu memaksakan kepercayaannya kepada orang lain</p>', '<p>Tetap menghargai keyakinan orang lain</p>', '<p>Tidak perlu memaksakan kehendak, cukup disampaikan saja</p>', '5', '1', '4', '3', '2', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:00:25', '2024-09-16 04:00:25'),
(179, '<p>Suatu hari seorang teman Erik mengajak Erik untuk ikut berpartisipasi dalam organisasi yang bercita- cita mendirikan negara dengan dasar agama yang pada akhirnya mampu menyatukan berbagai batas-batas negara tertentu. Sikap Erik terhadap ajakan tersebut adalah</p>', 'TKP', 'Random', NULL, '<p>Menolak dengan tegas karena hal tersebut berbahaya bagi keutuhan NKRI</p>', '<p>Erik akan bergabung ke organisasi tersebut karena mendukung gagasan menggabungkan negara negara seagama untuk kejayaan dunia</p>', '<p>Layak dipertimbangkan ajakan tersebut karena paham negara Indonesia tidak sesuai dengan keyakinan Erik</p>', '<p>Erik akan ikut berjuang di organisasi tersebut karena sesuai dengan keimanan Erik</p>', '<p>Erik belum dapat mengambil sikap sebelum Erik pelajari dulu organisasi tersebut</p>', '5', '3', '1', '2', '4', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:01:25', '2024-09-16 04:01:25'),
(180, '<p>Tomi adalah PNS di salah satu instansi pemerintah yang memiliki tetangga yang suka menghasut warga di media sosial untuk menentang dan membenci pemerintah yang sah beserta kelompok- kelompok tertentu yang mengarah ke SARA. Sikap yang tepat bagi Tomi untuk merespon hal tersebut adalah</p>', 'TKP', 'Random', NULL, '<p>Mendukung sikap tetangga Tomi tersebut karena Tomi meyakini pemerintah telah melakukan banyak pelanggaran terhadap keimanan yang Tomi anut</p>', '<p>Mempertimbangkan pernyataan yang dibuat oleh tetangga Tomi adalah benar jadi Tomi tidak mempermasalahkan</p>', '<p>Tomi menganggap ini adalah bentuk kebebasan berekspresi dan berpendapat meskipun Tomi kurang menyetujuinya</p>', '<p>Tomi berpura pura tidak tahu atas tulisan tetangga Tomi di media sosial karena bukan urusan Tomi</p>', '<p>Tomi akan menegur tetangga Tomi langsung secara baik-baik. karena hal tersebut berbahaya untuk stabilitas NKRI</p>', '1', '3', '4', '2', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 04:02:09', '2024-09-16 04:02:09'),
(181, '<p>Jefri bekerja di sebuah kantor pelayanan pajak. Suatu hari, atasan Jefri dipromosikan menjadi kepala kantor di unit tempat Jefri bekerja. Saat terjadi kekosongan atasan, Jefri diberikan tugas untuk menjadi pelaksana tugas yang sebelumnya di pimpin oleh atasannya. Jefri akan ...</p>', 'TKP', 'Random', NULL, '<p>Meminta waktu untuk memikirkannya</p>', '<p>Menerima dan melaksanakan dengan sebaik mungkin</p>', '<p>Menolaknya karena beban kerjanya sungguh berat</p>', '<p>Menolak dan menyarankan teman lain untuk menggantikan Jefri&nbsp;</p>', '<p>Menerima dan meminta bantuan teman untuk membantu Jefri&nbsp;</p>', '3', '5', '1', '2', '4', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 04:02:48', '2024-09-16 04:02:48'),
(182, '<p>Putra merupakan seorang pegawai yang ditugaskan sebagai panitia stand pameran. Kala itu ia mendapat umpan balik secara langsung dari masyarakat yang menyatakan bahwa materi yang dipamerkan cenderung monoton sehingga kurang menarik. Bila Anda adalah Putra, bagaimana reaksi Anda?</p>', 'TKP', 'Random', NULL, '<p>Saya dengan sigap mencatat umpan balik yang relevan dengan tujuan sebagai pertimbangan untuk pameran selanjutnya</p>', '<p>Hanya beberapa umpan balik yang saya catat dan saya berikan penjelasannya kepada orang tersebut</p>', '<p>Menerima umpan balik yang relevan dan segera mengubah sesuai dengan rekomendasi dari masyarakat tersebut</p>', '<p>Memberikan senyuman kepada masyarakat yang telah memberikan umpan balik dan berterimakasih atas kepeduliannya</p>', '<p>Saya berterimakasih lalu mendiskusikan umpan balik yang disampaikan untuk dapat dipahami dan diterapkan pada pameran selanjutnya</p>', '3', '1', '4', '2', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 04:03:32', '2024-09-16 04:03:32'),
(183, '<p>Toni terpaksa melanggar aturan lalu lintas karena terburu-buru hendak ujian CPNS di salah satu instansi. Ia marah-marah saat di tilang polisi karena merasa ujian lebih penting. Jika Anda sebagai polisi yang sedang bertugas, maka tindakan Anda adalah</p>', 'TKP', 'Random', NULL, '<p>Menilang Toni dengan cepat dan tenang, serta memberi penjelasan agar ia tidak melanggar di kemudian hari</p>', '<p>Tidak mendengarkan omongan Toni, tetap fokus pada tanggung jawab terhadap tugas menilang</p>', '<p>Menjelaskan pelanggaran lalu lintas yang dilakukan oleh Toni dengan suara yang tegas agar ia jera</p>', '<p>Memberikan pemahaman secara baik-baik meskipun mulai emosi karena Toni tidak merasa bersalah</p>', '<p>Mengendalikan diri agar tidak ikut marah dan menilang dengan cepat agar Toni tidak terlambat mengikuti ujian</p>', '4', '3', '1', '2', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 04:04:13', '2024-09-16 04:04:13'),
(184, '<p>Wisnu bekerja sebagai petugas pelayanan sebuah perusahaan asuransi. Pada hari itu perasaan Wisnu sedang kurang baik karena ada tadi pagi baru saja cekcok dengan istrinya. Sikap Wisnu pada hari itu ketika harus menghadapi klien sebaiknya....</p>', 'TKP', 'Random', NULL, '<p>tetap melayani pelanggan dengan kondisi perasaan yang tidak stabil</p>', '<p>Menolak melayani pelanggan dengan alasan kondisi emosi sedang kurang stabil</p>', '<p>Menolak melayani pelanggan dengan alasan kurang enak badan dan izin pulang</p>', '<p>Meminta teman untuk menggantikan Wisnu sementara Wisnu menenangkan diri</p>', '<p>Menenangkan diri lalu tetap melayani pelanggan dengan optimal</p>', '3', '1', '2', '4', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 04:04:52', '2024-09-16 04:04:52');
INSERT INTO `questions` (`id`, `question`, `scoring_type`, `category`, `image`, `option_a`, `option_b`, `option_c`, `option_d`, `option_e`, `poin_a`, `poin_b`, `poin_c`, `poin_d`, `poin_e`, `image_a`, `image_b`, `image_c`, `image_d`, `image_e`, `correct_option`, `created_at`, `updated_at`) VALUES
(185, '<p>Seseorang ingin mengirimkan hewan ternak melalui pelabuhan, tetapi tidak memiliki surat kesehatan hewan yang dipersyaratkan. Setelah dilakukan pemeriksaan, ternyata hewan tersebut merupakan pembawa penyakit menular dan harus dimusnahkan. Maka Andri selaku petugas akan …</p>', 'TKP', 'Random', NULL, '<p>Langsung memusnahkan hewan tersebut dan mengupayakan ganti rugi untuk pemiliknya</p>', '<p>Menginformasikan kepada pemilik ternak bahwa hewan harus dimusnahkan dan tidak bisa dikirim</p>', '<p>Menginformasikan kepada atasan terkait kasus tersebut&nbsp;</p>', '<p>Langsung memusnahkan hewan tersebut sesuai prosedur</p>', '<p>Meminta kepada pemilik hewannya dengan syarat harus dimusanahkan</p>', '2', '4', '3', '5', '1', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:05:50', '2024-09-16 04:05:50'),
(186, '<p>Dika memiliki seorang teman yang sangat dekat karena sudah bersama sejak duduk di sekolah dasar. Pada suatu waktu, teman Dika meminjam sejumlah uang untuk membayar kos-kosan dan berjanji akan mengembalikannya setelah beberapa minggu. Namun ternyata sudah hampir dua bulan dia belum mengembalikannya juga. Bila Anda adalah Dika, maka Anda akan...</p>', 'TKP', 'Random', NULL, '<p>Segera menghubunginya untuk menanyakan perihal utang tersebut karena sudah melewati janji pengembaliannya</p>', '<p>Segera menghubunginya untuk menanyakan perihal hutang tersebut karena saya juga membutuhkan uang tersebut</p>', '<p>Menemuinya seperti biasa dan jika ada kesempatan akan menanyakan tentang utang tersebut&nbsp;</p>', '<p>Menghubunginya dan memintanya menemui saya untuk membicarakan utangnya tersebut&nbsp;</p>', '<p>Meminta komitmennya untuk kejelasan pengembalian pinjaman karena saya juga butuh uang tersebut</p>', '5', '4', '1', '2', '3', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:06:45', '2024-09-16 04:06:45'),
(187, '<p>Anda diminta atasan anda untuk menyelesaikan sebuah masalah di dalam pekerjaan karena atasan anda menilai anda karyawan yang paling mampu mengatasinya dengan baik dan efektif. Namun ketika di tengah jalan penyelesaian yang anda berikan terhadap permasalahan tersebut sedikit kurang optimal untuk memberikan solusi terbaik seperti yang diharapkan perusahaan, yang anda lakukan adalah...</p>', 'TKP', 'Random', NULL, '<p>Saya meminta atasan untuk memberikan saya waktu lebih untuk memikirkannya</p>', '<p>Saya melakukan modifikasi atas keputusan tersebut, terkadang modifikasi kecil sudah cukup</p>', '<p>Saya akan merubah semua solusi yang ada dan membuat penyelesaian baru</p>', '<p>Saya meminta atasan untuk memberikan saya waktu lebih untuk memikirkannya</p>', '<p>Memikirkan cara yang paling efektif dari penyelesaian sebelumnya</p>', '2', '5', '3', '1', '4', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 04:08:07', '2024-09-16 04:08:07'),
(188, '<p>Putri Pak Andi satu-satunya ingin melanjutkan pendidikan yang lebih baik ke kota dan harus hidup terpisah dengan Pak Andi. Hal ini menjadi dilema karena Pak Andi khawatir pergaulan perkotaan akan mengubah anaknya menjadi tidak baik. Sikap Pak Andi …..</p>', 'TKP', 'Random', NULL, '<p>Membebaskannya melakukan apa yang ia mau, hal ini karena ia sudah dewasa.</p>', '<p>Tidak memberikan izin karena khawatir ia harus hidup sendirian di kota berbahaya.</p>', '<p>Tidak peduli pada keinginannya. Hal ini karena saya mengharuskannya kuliah di dekat rumah.</p>', '<p>Mengizinkan dengan syarat-syarat tertentu, agar memastikannya fokus pada pendidikan.</p>', '<p>Memberi pengertian dan menawarkan alternatif sekolah di dekat rumah.</p>', '4', '2', '1', '5', '3', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:08:48', '2024-09-16 04:08:48'),
(189, '<p>Siska bekerja sebagai petugas survey di suatu perusahaan. Selama ini, survey dilakukan secara manual dari satu responden ke responden lain dan dicatat dalam sebuah log book untuk kemudian disalin dalam bentuk excel. Namun, belakang ini banyak data survey yang salah akibat adanya human error atau kesalahan petugas ketika input data. Setelah survey selesai, diadakan evaluasi dan Siska diminta untuk mengusulkan ide agar kesalahan dapat dicegah sejak dini. Apa yang akan Siska sampaikan ketika evaluasi?</p>', 'TKP', 'Random', NULL, '<p>Mengusulkan penambahan petugas input yang berbeda dengan petugas survey agar masing-masing proses dapat berjalan dengan maksimal</p>', '<p>Tetap melaksanakan SOP lama, karena sudah diterapkan di perusahaan selama puluhan tahun</p>', '<p>Mengusulkan penambahan jumlah gawai yang lebih canggih agar proses input data berjalan lebih akurat</p>', '<p>Mengusulkan penggunaan digitalisasi menggunakan aplikasi yang mudah dimengerti dan efisien</p>', '<p>Menyampaikan kendala yang ada ketika di lapangan dan mencari solusi bersama dalam rapat</p>', '2', '1', '3', '5', '4', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:09:25', '2024-09-16 04:09:25'),
(190, '<p>Ada warga baru di kompleks perumahan Rudi. Ia datang menemui Rudi dan membahas program RT yang menurutnya tidak jelas dan hanya menyusahkan warganya. Rudi sudah mencoba jelaskan namun warga baru tersebut kasar dan sikapnya sombong. Sikap Rudi adalah ...&nbsp;</p>', 'TKP', 'Random', NULL, '<p>Memintanya datang ke rumah ketua RT untuk mendapatkan penjelasan dari program tersebut</p>', '<p>Sebagai warga lama, Rudi menjelaskan program tersebut dan memintanya untuk bisa beradaptasi</p>', '<p>Mengantarkannya ke rumah ketua RT dan meminta penjelasan tentang program tersebut</p>', '<p>Mendiamkannya karena sikapnya kasar dan memintanya datang ke rumah ketua RT&nbsp;</p>', '<p>Menerima usulannya dan menyampaikan kepada ketua RT&nbsp;</p>', '4', '3', '5', '1', '2', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 04:10:02', '2024-09-16 04:10:02'),
(191, '<p>Rudi adalah seorang atasan perusahaan konstruksi di kota X. Suatu hari Rudi harus bertemu dengan klien untuk mempresentasikan produk yang akan ditawarkan kepada klien tersebut. Oleh karena itu, Rudi meminta salah satu karyawan untuk menyiapkan bahan presentasi. Namun pada saat hari presentasi, karyawan tersebut tidak hadir tanpa info apapun. Rudi sudah berusaha menghubunginya berulang kali, tapi tidak ada balasan dari karyawan tersebut. Tindakan yang akan Rudi lakukan pada kondisi itu adalah …</p>', 'TKP', 'Random', NULL, '<p>Segera membuat bahan presentasi sebelum presentasi dimulai dan meminta staf lain untuk menghubungi karyawan tersebut dengan harapan karyawan tersebut dapat mengirimkan file bahan presentasi melalui email</p>', '<p>Meminta karyawan lain untuk membuat bahan presentasi secara cepat dengan deskripsi produk yang sudah Rudi jelaskan sehingga presentasi tetap dapat terlaksana pada hari itu</p>', '<p>Membuat bahan presentasi sebelum presentasi dimulai karena Rudi sudah memahami deskripsi produk yang akan ditawarkan kepada klien</p>', '<p>Menghubungi klien dan meminta maaf karena harus mengundurkan hari presentasi dengan alasan karyawan yang sudah menyiapkan bahan presentasi tdak hadir ke kantor dan sulit untuk dihubungi&nbsp;</p>', '<p>Terus mencoba menghubunginya dengan harapan ada balasan dari karyawan tersebut dan dapat mengirimkan file bahan presentasi melalui email sehingga presentasi tetap dapat terlaksana pada hari itu</p>', '5', '3', '4', '1', '2', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:11:58', '2024-09-16 04:11:58'),
(192, '<p>Fikri adalah seorang lulusan sarjana yang ingin menjadi seorang Aparatul Sipil Negara. Jika Fikri nanti telah menjadi seorang ASN maka&nbsp;</p>', 'TKP', 'Random', NULL, '<p>Dalam bekerja, Fikri tidak akan berhenti bekerja sampai pekerjaan selesai</p>', '<p>Dalam bekerja Fikri akan selalu tekun dan ikhlas</p>', '<p>Dalam bekerja, Fikri akan selalu bersemangat dan profesional</p>', '<p>Dalam bekerja, Fikri akan selalu bekerja sama dengan baik dengan rekan kerja</p>', '<p>Dalam bekerja, Fikri akan selalu mengikuti arahan atasan</p>', '1', '2', '5', '4', '3', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 04:12:38', '2024-09-16 04:12:38'),
(193, '<p>Pada saat Galih mendapatkan kesempatan untuk mendapatkan pendanaan atas ide usaha Galih. Syaratnya Adalah Galih harus bisa menarik minat investor dengan proposal yang Galih ajukan. Namun, proposal yang Galih buat di tolak oleh calon investor dengan alasan kurang visioner. Sikap Galih ...</p>', 'TKP', 'Random', NULL, '<p>Melakukan perbaikan atas proposal tersebut dan mengajukan kembali</p>', '<p>Membuat tampilan proposal Galih lebih menarik tanpa mengubah isinya</p>', '<p>Berusaha mencari calon investor lain yang tertarik</p>', '<p>Menerima penolakan tersebut sebagai bahan evaluasi ke depannya</p>', '<p>Menerima penolakan tersebut sebagai bahan evaluasi ke depannya</p>', '5', '2', '1', '3', '4', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:16:31', '2024-09-16 04:16:31'),
(194, '<p>Menghadapi era Revolusi Industri 4.0, kantor Andri diminta berbenah ke arah yang lebih baik. Pimpinan menginginkan adanya perubahan yang drastis dengan penggunaan teknologi terbaru yang ada. Akan tetapi, keinginan itu hanya sekadar ucapan saja tanpa ada tindakan nyata dari pimpinan. Andri sebagai generasi milenial yang baru masuk ke kantor tersebut akan...</p>', 'TKP', 'Random', NULL, '<p>Tetap mengikuti budaya kantor yang ada dengan tetap berpegang teguh pada peraturan dan SOP yang ada</p>', '<p>Mengusulkan implementasi teknologi terbaru di rapat bulanan dan bersedia ditunjuk sebagai PIC-nya</p>', '<p>Mencoba untuk mengimplementasikan teknologi terbaru yang ada dengan izin dari pimpinan</p>', '<p>Langsung memakai teknologi yang terbaru karena sangat memudahkan pekerjaan yang ada</p>', '<p>Menjadikan hal ini sebagai dasar bahan kajian untuk perubahan kantor tahun berikutnya</p>', '1', '4', '5', '3', '2', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 04:17:17', '2024-09-16 04:17:17'),
(195, '<p>Ketika Oki sedang melakukan perjalanan dinas di luar kota dimana penugasannya selama 2 minggu, tiba-tiba Oki ditelepon oleh istrinya yang sedang hamil tua mengabarkan bahwa dia akan segera melahirkan anak Oki yang pertama. Mendengar kabar ini, apa yang akan Oki lakukan karena lokasi kota penugasan dengan rumah Oki sangat jauh dan harus menggunakan beberapa alat transportasi?</p>', 'TKP', 'Random', NULL, '<p>Segera meminta izin pimpinan agar bisa pulang menemani persalinan istri Oki</p>', '<p>Tetap melanjutkan hingga penugasan selesai baru kemudian pulang</p>', '<p>Meminta izin untuk pulang beberapa hari kemudian melanjutkan penugasan lagi</p>', '<p>Menelpon istri setiap hari untuk mengetahui kondisinya dan meminta maaf tidak bisa menemani persalinan</p>', '<p>Menelpon keluarga terdekat untuk menemani istri persalinan karena Oki tidak bisa kembali ke rumah</p>', '1', '2', '4', '3', '5', NULL, NULL, NULL, NULL, NULL, 'e', '2024-09-16 04:17:56', '2024-09-16 04:17:56'),
(196, '<p>Suatu ketika Rafi dikejutkan dengan keluarnya atasan Rafi dari perusahaan. Rafi kehilangan sosok atasan yang memastikan setiap project yang Rafi kerjakan sukses. Rafi khawatir pengganti atasan Rafi tidak memiliki visi yang sama atau mudah diajak bekerja sama seperti atasan Rafi yang keluar perusahaan. Sikap Rafi adalah &nbsp;...</p>', 'TKP', 'Random', NULL, '<p>Menahan diri Rafi untuk menilai gayanya bekerja</p>', '<p>Menahan diri Rafi untuk menilai kompetensinya sampai beliau sudah mengerti posisinya</p>', '<p>Berpikir positif bahwa bisa jadi tidak seburuk itu dan bahkan mungkin sama baiknya dengan atasan Rafi yang lama</p>', '<p>Mencoba mengenali pribadinya dan gaya kepemimpinannya serta arah kebijakannya</p>', '<p>Tetap bekerja seperti biasa karena pada akhirnya bagi Rafi penggantian atasan bukanlah sebuah masalah yang berarti</p>', '1', '2', '3', '5', '4', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:18:36', '2024-09-16 04:18:36'),
(197, '<p>Masalah di tempat kerja yang bisa menimpa siapa pun adalah pekerjaan yang tidak sesuai dengan ekspektasi Anda saat melamarnya. Misalkan pada tahap rekrutmen Anda ingin ditempatkan di bagian IT sesuai dengan program studi pada saat kuliah, namun berakhir dengan menyusun laporan keuangan setiap harinya. Sikap Anda adalah</p>', 'TKP', 'Random', NULL, '<p>Menanyakan kepada atasan mengapa sewaktu Anda direkrut untuk perusahaan Anda, pekerjaan yang ditawarkan berbeda dengan kenyataan di lapangan</p>', '<p>Menerima dengan ikhlas dan tetap bekerja seperti biasa</p>', '<p>Menerimanya dan berusaha meningkatkan kompetensi di bidang pekerjaan Anda saat ini</p>', '<p>Meminta pada atasan apakah Anda bisa diusulkan untuk dipindah ke bagian IT</p>', '<p>Memaklumi karena perubahan perencanaan kebutuhan SDM bisa berubah sewaktu-waktu</p>', '1', '4', '5', '3', '2', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 04:19:21', '2024-09-16 04:19:21'),
(198, '<p>Performance management merupakan hal penting dalam mempertahankan kualitas sumber daya manusia dalam suatu organisasi. Gilang adalah seorang kepala seksi pelayanan data dan informasi. Anak buah Gilang mengerjakan pekerjaannya dengan sangat baik melebihi target yang diberikan. Yang Gilang lakukan adalah ...</p>', 'TKP', 'Random', NULL, '<p>Memberinya sedikit penghargaan dan memintanya untuk meningkatkan prestasi kerjanya&nbsp;</p>', '<p>Memujinya dan menyemangatinya supaya dia semakin termotivasi</p>', '<p>Memberikannya target yang sedikit lebih tinggi</p>', '<p>Mengusulkannya untuk promosi jabatan</p>', '<p>Menganggap itu sebagai prestasi yang wajar</p>', '5', '4', '2', '3', '1', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:20:00', '2024-09-16 04:20:00'),
(199, '<p>Perubahan adalah suatu hal yang pasti. Kebijakan yang dilakukan oleh organisasi selalu ditujukan untuk pencapaian visi organisasi. Suatu hari pimpinan memberikan arahan bahwa kita perlu mencontoh konsep open space karena penelitian menunjukkan hal itu bisa menggenjot produktivitas dan meningkatkan kolaborasi. Anda harus berbagi ruangan dengan seorang rekan kerja. Padahal Anda merasa lebih nyaman bekerja sendiri dalam ruangan. Yang Anda lakukan adalah ...</p>', 'TKP', 'Random', NULL, '<p>Tetap bekerja seperti biasa</p>', '<p>Meminta pertimbangan apakah konsep open space sangat urgent dibutuhkan</p>', '<p>Membiasakan diri dan membangun suasana kerja yang menyenangkan</p>', '<p>Bekerja dengan menggunakan noise cancelling headphone agar tidak terganggu sekitar&nbsp;</p>', '<p>Pindah ke ruangan lain yang kosong</p>', '4', '2', '5', '3', '1', NULL, NULL, NULL, NULL, NULL, 'c', '2024-09-16 04:20:36', '2024-09-16 04:20:36'),
(200, '<p>Dwi adalah seorang PNS yang baru saja ditempatkan di kantor vertikal daerah yang mayoritas penduduknya beragama berbeda dengan Dwi. Dia ditempatkan di sana bersama 9 teman lainnya yang juga PNS baru. Pada saat akan ada libur hari besar keagamaan Dwi berencana mengambil cuti karena sudah setahun lebih tidak bertemu keluarganya di kampung halaman. Teman-temannya pun akan mengajukan cuti dimana 6 orang cuti untuk merayakan hari besar keagamaan di rumah sedangkan 4 lainnya termasuk Dwi untuk bertemu orang tua di rumah mumpung ada kesempatan libur lama. Dwi sudah terlanjur membeli tiket pesawat untuk pulang akan tetapi tiba-tiba dari kantor pusat jatah cuti untuk setiap kantor dibatasi. Kepala kantor pun memutuskan hanya sebagian kecil saja yang disetujui cutinya yaitu diprioritaskan yang merayakan hari besar keagamaan. Melihat kondisi ini, apa yang akan Dwi lakukan...</p>', 'TKP', 'Random', NULL, '<p>Meminta pengertian dari pimpinan karena telah terlanjur membeli tiket pesawat untuk pulang ke rumah</p>', '<p>Bersedia menunda cuti dengan syarat untuk libur kedepannya bisa bergantian</p>', '<p>Bersedia menunda cuti dan meminta atasan agar mengizinkan cuti pada hari yang lain</p>', '<p>Membatalkan tiket pesawat yang sudah dibeli dan mendahulukan yang akan merayakan hari besar keagamaan</p>', '<p>Mengajak rekan-rekan pegawai baru untuk berdiskusi mencari solusi terbaik</p>', '2', '1', '4', '5', '3', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:21:25', '2024-09-16 04:21:25'),
(201, '<p>Fahri adalah kepala divisi publikasi di sekolahnya. Sekolah Fahri meluncurkan perangkat lunak basis data kesiswaan sekolah. Kepala Sekolah menugasinya untuk membuat Iiputan terkait peluncuran aplikasi, meskipun disisi lain, fahri belum mengenal secara jelas kegunaan aplikasi tersebut. Menurut Fahri, dengan adanya aplikasi baru tersebut maka ...</p>', 'TKP', 'Random', NULL, '<p>Meyakini bahwa perangkat lunak basis data yang digunakan sekolah dapat memudahkan pekerjaan staf kesiswaan sekolah</p>', '<p>percaya bahwa perangkat lunak basis data yang baru dapat meningkatkan akreditasi sekolah dalam aspek pemanfaatan teknologi.</p>', '<p>meyakini bahwa perangkat lunak basis data yang digunakan sekolah belum penting untuk diterapkan sekarang</p>', '<p>meyakini bahwa ada teknologi yang bisa dimanfaatkan untuk kemajuan sekolah, tetapi ada juga yang tidak bisa dimanfaatkan</p>', '<p>meyakini bahwa perangkat lunak basis data dapat memudahkan pekerjaannya ketika mencari data kesiswaan</p>', '5', '4', '1', '2', '3', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:22:06', '2024-09-16 04:22:06'),
(202, '<p>Setiap pagi Erwin, melihat tetangganya menyimpan sampah-sampah di depan pintu pagar rumahnya, sehingga itu menimbulkan bau yang tidak sedap yang mengakibatkan banyak lalat di sekitar jalan rumahnya, dan itu pastinya mengganggu orang yang melintas, termasuk Erwin. Setiap Erwin pergi mengantor baju Erwin sering kurang enak karena berbau. Sedangkan petugas sampah tidak ingin mengangkutnya dikarenakan menunggak 4 bulan. Maka Erwin akan melakukan …..</p>', 'TKP', 'Random', NULL, '<p>Mendatangi rumahnya kemudian menjelaskan untuk tidak menyimpan sampah tersebut didepan rumahnya karena mengganggu</p>', '<p>Melaporkan kepada RT/RW tentang hal tersebut untuk dicarikan solusi bersama</p>', '<p>Membayarkan tunggakan sampah tersebut kepada petugas sampah</p>', '<p>Mengkomunikasikan kepada petugas sampah untuk minta tolong ambil kebijakan untuk mengambil sampahnya</p>', '<p>Biarkan saja, lama-lama juga tetangga Erwin akan merasakan ketidaknyamanannya</p>', '4', '5', '2', '3', '1', NULL, NULL, NULL, NULL, NULL, 'b', '2024-09-16 04:22:45', '2024-09-16 04:22:45'),
(203, '<p>Nilai dari hasil operasi bilangan berikut adalah</p>', 'TIU', 'Hitung Cepat', '1726461640.jpg', '<p>2</p>', '<p>3</p>', '<p>6</p>', '<p>8</p>', '<p>12</p>', '5', '0', '0', '0', '0', NULL, NULL, NULL, NULL, NULL, 'a', '2024-09-16 04:40:40', '2024-09-16 04:40:56'),
