(206, '<p>(625² – 375²) = …</p>', 'TIU', 'Hitung Cepat', NULL, '<p>125.000</p>', '<p>240.000</p>', '<p>120.000</p>', '<p>250.000</p>', '<p>520.000</p>', '0', '0', '0', '5', '0', NULL, NULL, NULL, NULL, NULL, 'd', '2024-09-16 04:45:42', '2024-09-16 04:45:42'),
